const d="Identity",p="Quick basics — just enough to make everything feel right from the start. 2 minutes, no wrong answers.",c={headline:"Identity locked in.",body:"AI now knows your name, language, and why you're here. First impression already 10x better than default. Next: how you like to communicate."},h=JSON.parse(`[{"id":"t0_q01","tier":0,"tier_name":"Identity","question":"What should AI call you?","type":"open_text","placeholder":"First name, nickname, or whatever feels right","skippable":false,"meta_profiling":"Length and type of name chosen. Nickname vs formal name signals informality preference. If they write a title (Dr., Mr.) — note formality.","dimension":"identity.preferred_name","why_this_matters":"AI uses this every time it addresses you. Gets personal fast."},{"id":"t0_q02","tier":0,"tier_name":"Identity","question":"What language should AI respond in by default?","type":"select","options":[{"value":"en","label":"English","maps_to":{"dimension":"identity.language","value":"en"}},{"value":"pl","label":"Polish / Polski","maps_to":{"dimension":"identity.language","value":"pl"}},{"value":"de","label":"German / Deutsch","maps_to":{"dimension":"identity.language","value":"de"}},{"value":"es","label":"Spanish / Español","maps_to":{"dimension":"identity.language","value":"es"}},{"value":"fr","label":"French / Français","maps_to":{"dimension":"identity.language","value":"fr"}},{"value":"other","label":"Other","maps_to":{"dimension":"identity.language","value":"other"},"triggers":["t0_q02a"]}],"skippable":false,"meta_profiling":"If they change language mid-profiling session — note code-switching pattern.","dimension":"identity.language","why_this_matters":"AI will match your language across all exported profiles."},{"id":"t0_q02a","tier":0,"tier_name":"Identity","question":"Which language?","type":"open_text","placeholder":"e.g. Italian, Japanese, Portuguese...","skippable":true,"is_followup":true,"parent_question":"t0_q02","meta_profiling":null,"dimension":"identity.language","why_this_matters":null},{"id":"t0_q03","tier":0,"tier_name":"Identity","question":"Where in the world are you?","type":"select","options":[{"value":"europe_central","label":"Central Europe (PL, CZ, SK, HU...)","maps_to":{"dimension":"identity.timezone_region","value":"CET"},"also_maps_to":{"dimension":"identity.date_format","value":"dd_mm_yyyy"}},{"value":"europe_west","label":"Western Europe (UK, DE, FR...)","maps_to":{"dimension":"identity.timezone_region","value":"WET/CET"}},{"value":"us_east","label":"US East Coast","maps_to":{"dimension":"identity.timezone_region","value":"ET"}},{"value":"us_west","label":"US West Coast","maps_to":{"dimension":"identity.timezone_region","value":"PT"}},{"value":"asia_pacific","label":"Asia / Pacific","maps_to":{"dimension":"identity.timezone_region","value":"APAC"}},{"value":"other","label":"Somewhere else","maps_to":{"dimension":"identity.timezone_region","value":"other"},"triggers":["t0_q03a"]}],"skippable":true,"meta_profiling":"Timezone affects date/time formatting, currency assumptions, holiday context.","dimension":"identity.timezone_region","why_this_matters":"Dates, times, and currency in AI responses adapt to your location."},{"id":"t0_q03a","tier":0,"tier_name":"Identity","question":"What's your timezone? (e.g. GMT+5, Tokyo, São Paulo...)","type":"open_text","placeholder":"City or UTC offset","skippable":true,"is_followup":true,"parent_question":"t0_q03","meta_profiling":null,"dimension":"identity.timezone","why_this_matters":null},{"id":"t0_q04","tier":0,"tier_name":"Identity","question":"How old are you? (roughly is fine)","type":"select","options":[{"value":"under_20","label":"Under 20","maps_to":{"dimension":"identity.age_range","value":"teen"}},{"value":"20_29","label":"20s","maps_to":{"dimension":"identity.age_range","value":"20s"}},{"value":"30_39","label":"30s","maps_to":{"dimension":"identity.age_range","value":"30s"},"also_maps_to":{"dimension":"communication.formality","value":"professional_casual"}},{"value":"40_49","label":"40s","maps_to":{"dimension":"identity.age_range","value":"40s"}},{"value":"50_plus","label":"50+","maps_to":{"dimension":"identity.age_range","value":"50+"}},{"value":"skip","label":"Prefer not to say","maps_to":{"dimension":"identity.age_range","value":"unknown"}}],"skippable":true,"meta_profiling":"Age affects cultural references, generational communication defaults, and tech comfort assumptions.","dimension":"identity.age_range","why_this_matters":"AI calibrates cultural references and explanations to what actually resonates for your generation."},{"id":"t0_q05","tier":0,"tier_name":"Identity","question":"How do you identify? (for AI to use correct pronouns)","type":"select","options":[{"value":"he","label":"He / Him","maps_to":{"dimension":"identity.pronouns","value":"he/him"}},{"value":"she","label":"She / Her","maps_to":{"dimension":"identity.pronouns","value":"she/her"}},{"value":"they","label":"They / Them","maps_to":{"dimension":"identity.pronouns","value":"they/them"}},{"value":"no_preference","label":"No preference — doesn't matter","maps_to":{"dimension":"identity.pronouns","value":"neutral"}},{"value":"skip","label":"Skip this one","maps_to":{"dimension":"identity.pronouns","value":"unknown"}}],"skippable":true,"meta_profiling":null,"dimension":"identity.pronouns","why_this_matters":"AI uses correct pronouns when referring to you — small thing, big difference."},{"id":"t0_q06","tier":0,"tier_name":"Identity","question":"What's the main reason you're building this profile?","type":"select","options":[{"value":"better_chat","label":"Better conversations with AI","description":"ChatGPT, Claude, Gemini — want AI to understand me without re-explaining","maps_to":{"dimension":"identity.primary_use_case","value":"chat_ai"},"triggers":[]},{"value":"dev_tools","label":"AI coding assistant setup","description":"Cursor, Copilot, Claude Code — want my dev tools to know my style","maps_to":{"dimension":"identity.primary_use_case","value":"dev_tools"},"also_maps_to":{"dimension":"identity.tech_comfort","value":"advanced"},"triggers":[]},{"value":"local_llm","label":"Local / private AI (Ollama, LM Studio...)","description":"Running AI on my own machine, want it personalized","maps_to":{"dimension":"identity.primary_use_case","value":"local_llm"},"also_maps_to":{"dimension":"identity.tech_comfort","value":"expert"},"triggers":[]},{"value":"all_of_it","label":"All of the above — I use many AI tools","maps_to":{"dimension":"identity.primary_use_case","value":"multi_platform"},"triggers":[]}],"skippable":false,"meta_profiling":"Use case selected affects which export formats are prioritized in the export center. Dev tools selection = likely higher tech comfort.","dimension":"identity.primary_use_case","why_this_matters":"Shapes which export formats get recommended at the end."},{"id":"t0_q07","tier":0,"tier_name":"Identity","question":"What do you do? (broadly — no need to be exact)","type":"select","options":[{"value":"developer","label":"Software developer / engineer","maps_to":{"dimension":"identity.professional_role","value":"developer"},"also_maps_to":{"dimension":"communication.code_preference","value":"code_over_prose"}},{"value":"designer","label":"Designer / Creative","maps_to":{"dimension":"identity.professional_role","value":"designer"}},{"value":"founder","label":"Founder / Entrepreneur","maps_to":{"dimension":"identity.professional_role","value":"founder"},"also_maps_to":{"dimension":"work.decision_style","value":"autonomous"}},{"value":"manager","label":"Manager / Team lead","maps_to":{"dimension":"identity.professional_role","value":"manager"},"also_maps_to":{"dimension":"communication.summary_preference","value":"executive_summary"}},{"value":"knowledge_worker","label":"Writer / Researcher / Analyst","maps_to":{"dimension":"identity.professional_role","value":"knowledge_worker"}},{"value":"student","label":"Student","maps_to":{"dimension":"identity.professional_role","value":"student"},"also_maps_to":{"dimension":"communication.explanation_depth","value":"thorough_with_examples"}},{"value":"other","label":"Something else entirely","maps_to":{"dimension":"identity.professional_role","value":"other"},"triggers":["t0_q07a"]}],"skippable":true,"meta_profiling":"Professional role shapes default jargon tolerance, autonomy expectations, and which domains AI should fluency-adjust for.","dimension":"identity.professional_role","why_this_matters":"AI picks up the right vocabulary for your field and adjusts how deep it goes on technical topics."},{"id":"t0_q07a","tier":0,"tier_name":"Identity","question":"What's your field or role?","type":"open_text","placeholder":"e.g. nurse, chef, musician, teacher...","skippable":true,"is_followup":true,"parent_question":"t0_q07","meta_profiling":null,"dimension":"identity.professional_role","why_this_matters":null},{"id":"t0_q08","tier":0,"tier_name":"Identity","question":"On a scale of 0 to 10 — how tech-comfortable are you?","type":"spectrum","spectrum":{"min":0,"max":10,"min_label":"I use apps and Google things","max_label":"I build software for fun","midpoint_label":"Comfortable but not a developer"},"options":[{"value":"0_3","label":"0-3: Apps are my thing","maps_to":{"dimension":"identity.tech_comfort","value":"non_technical"}},{"value":"4_6","label":"4-6: Comfortable, not a dev","maps_to":{"dimension":"identity.tech_comfort","value":"moderate"}},{"value":"7_9","label":"7-9: I code and tinker","maps_to":{"dimension":"identity.tech_comfort","value":"technical"},"also_maps_to":{"dimension":"communication.jargon_level","value":"full_technical"}},{"value":"10","label":"10: I build things for other people","maps_to":{"dimension":"identity.tech_comfort","value":"expert"}}],"skippable":true,"meta_profiling":"Observe how they answer this question itself — if they spend time on it vs pick immediately. High self-awareness = note. Affects how profiling UI simplifies or deepens in later tiers.","dimension":"identity.tech_comfort","why_this_matters":"AI adjusts how it explains technical things — no jargon for non-devs, no hand-holding for experts."},{"id":"t0_q09","tier":0,"tier_name":"Identity","question":"One last quick one: what's your single biggest frustration with AI assistants right now?","type":"select","options":[{"value":"too_generic","label":"Responses feel generic, like they're for everyone","maps_to":{"dimension":"identity.ai_frustration","value":"generic_output"},"also_maps_to":{"dimension":"communication.personalization","value":"always_use_context"}},{"value":"too_verbose","label":"Way too long-winded and preachy","maps_to":{"dimension":"identity.ai_frustration","value":"verbosity"},"also_maps_to":{"dimension":"communication.response_length","value":"short"},"triggers":["t1_q02"]},{"value":"re_explain","label":"I have to re-explain my context every single time","maps_to":{"dimension":"identity.ai_frustration","value":"context_loss"},"also_maps_to":{"dimension":"communication.continuity","value":"reference_earlier"}},{"value":"format","label":"Wrong format — essays when I need bullets, bullets when I need detail","maps_to":{"dimension":"identity.ai_frustration","value":"format_mismatch"},"also_maps_to":{"dimension":"communication.format_preference","value":"adaptive"},"triggers":["t1_q06"]},{"value":"platform_switching","label":"I use 3+ AI tools and have to configure each one","maps_to":{"dimension":"identity.ai_frustration","value":"platform_friction"}}],"skippable":true,"meta_profiling":"This is a high-signal question. Frustration chosen = highest-priority dimension to nail. If 'too verbose' — already learn they want concise. If 'format' — format questions in Tier 1 are critical for them.","dimension":"identity.ai_frustration","why_this_matters":"Meport attacks your biggest frustration first."}]`),t={tier:0,tier_name:d,tier_intro:p,tier_complete:c,questions:h},_=1,g="Communication DNA",y="This is the one that makes the biggest immediate difference. How does AI talk TO you? Direct or careful? Short or detailed? With humor or straight? 3-5 minutes and your AI suddenly feels like it knows you.",v={headline:"Communication profile built.",body:"AI now knows exactly how to talk to you — the format, the tone, the level of directness. This alone eliminates 80% of 'ugh, not again' moments. Next: how you think and process information."},f=JSON.parse(`[{"id":"t1_q01","tier":1,"tier_name":"Communication DNA","question":"You ask AI something and get a 6-paragraph response when you wanted a quick answer. Your reaction?","type":"scenario","options":[{"value":"annoyed","label":"Mildly annoyed — I just skim to the actual answer","description":"I don't need the build-up","maps_to":{"dimension":"communication.verbosity_preference","value":"concise"}},{"value":"really_annoyed","label":"Genuinely frustrated — this is the #1 thing that bothers me","description":"I want the answer, not an essay","maps_to":{"dimension":"communication.verbosity_preference","value":"minimal"},"triggers":["t1_q01a"]},{"value":"depends","label":"Depends on the question — complex topics deserve more","maps_to":{"dimension":"communication.verbosity_preference","value":"adaptive"}},{"value":"fine","label":"Fine with it — I like seeing the full reasoning","maps_to":{"dimension":"communication.verbosity_preference","value":"detailed"}}],"skippable":false,"meta_profiling":"How long is their own response to this question? Short = minimal preference validated. Note if they justify their choice extensively — ironic signal of verbosity comfort.","dimension":"communication.verbosity_preference","why_this_matters":"Calibrates default response length across all AI exports."},{"id":"t1_q01a","tier":1,"tier_name":"Communication DNA","question":"What's your ideal default response style?","type":"select","is_followup":true,"parent_question":"t1_q01","options":[{"value":"one_to_three_lines","label":"1-3 lines for simple things, expand only if asked","maps_to":{"dimension":"communication.default_length","value":"ultra_short"}},{"value":"bullet_first","label":"Bullet points by default, no preamble","maps_to":{"dimension":"communication.default_length","value":"bullets_only"}},{"value":"short_paragraphs","label":"Short paragraphs, max 5-7 lines","maps_to":{"dimension":"communication.default_length","value":"short"}}],"skippable":true,"meta_profiling":null,"dimension":"communication.default_length","why_this_matters":null},{"id":"t1_q02","tier":1,"tier_name":"Communication DNA","question":"A friend texts you: 'Just give it to me straight, I can handle it.' That phrase feels...","type":"scenario","options":[{"value":"exactly_me","label":"Exactly how I'd say it myself","maps_to":{"dimension":"communication.directness","value":"blunt"},"also_maps_to":{"dimension":"communication.hedge_words","value":"avoid"}},{"value":"relatable","label":"Relatable — I generally prefer directness","maps_to":{"dimension":"communication.directness","value":"direct"}},{"value":"context_dependent","label":"Depends — direct for facts, softer for emotional stuff","maps_to":{"dimension":"communication.directness","value":"context_sensitive"}},{"value":"prefer_tact","label":"I prefer tact — directness without warmth feels harsh","maps_to":{"dimension":"communication.directness","value":"diplomatic"}}],"skippable":false,"meta_profiling":"How they answer — length, whether they add caveats ('it depends on...') — is itself a directness signal. Short pick = direct. Long explanation = diplomatic.","dimension":"communication.directness","why_this_matters":"Shapes how AI delivers assessments, feedback, and bad news."},{"id":"t1_q03","tier":1,"tier_name":"Communication DNA","question":"When AI explains something, what format makes it land best for you?","type":"ranking","instruction":"Drag to rank from most to least useful (or just pick your top 2)","options":[{"value":"bullet_points","label":"Bullet points","description":"Quick, scannable, digestible","maps_to":{"dimension":"communication.format_preference","value":"bullets"}},{"value":"numbered_steps","label":"Numbered steps","description":"Sequential, clear order","maps_to":{"dimension":"communication.format_preference","value":"numbered"}},{"value":"prose","label":"Flowing prose","description":"Natural writing, no fragmentation","maps_to":{"dimension":"communication.format_preference","value":"prose"}},{"value":"tables","label":"Tables / comparisons","description":"Side-by-side structure for options","maps_to":{"dimension":"communication.format_preference","value":"tables"}},{"value":"code_blocks","label":"Code / technical blocks","description":"Formatted, copyable","maps_to":{"dimension":"communication.format_preference","value":"code"}}],"max_selections":2,"skippable":true,"meta_profiling":"If user selects prose AND bullets — note format_preference as adaptive. Code blocks selection correlates with tech_comfort >= 7.","dimension":"communication.format_preference","why_this_matters":"AI defaults to your preferred structure instead of whatever it feels like."},{"id":"t1_q04","tier":1,"tier_name":"Communication DNA","question":"Emojis in AI responses — your honest take?","type":"select","options":[{"value":"hate_them","label":"Please no. They make it feel fake and childish.","maps_to":{"dimension":"communication.emoji_preference","value":"none"}},{"value":"sparingly","label":"Occasionally fine — just not every sentence","maps_to":{"dimension":"communication.emoji_preference","value":"sparingly"}},{"value":"neutral","label":"I don't really notice them either way","maps_to":{"dimension":"communication.emoji_preference","value":"neutral"}},{"value":"like_them","label":"I like them — adds personality and clarity","maps_to":{"dimension":"communication.emoji_preference","value":"frequent"}}],"skippable":true,"meta_profiling":"Did they use any emojis in their own answers during profiling? Cross-reference with stated preference. Incongruence = note.","dimension":"communication.emoji_preference","why_this_matters":"Sounds trivial, but it's one of the top complaints about AI tone."},{"id":"t1_q05","tier":1,"tier_name":"Communication DNA","question":"AI just finished explaining something and ends with 'Let me know if you'd like me to elaborate or if you have any questions!' — you feel...","type":"scenario","options":[{"value":"filler_hate","label":"This is exactly the filler I want gone","description":"If I want more, I'll ask","maps_to":{"dimension":"communication.filler_tolerance","value":"zero"},"also_maps_to":{"dimension":"communication.pleasantries","value":"skip"}},{"value":"mildly_annoyed","label":"Mildly annoying, but not a dealbreaker","maps_to":{"dimension":"communication.filler_tolerance","value":"low"}},{"value":"fine","label":"Fine — helpful reminder that I can continue","maps_to":{"dimension":"communication.filler_tolerance","value":"moderate"}},{"value":"dont_notice","label":"Honestly don't notice it","maps_to":{"dimension":"communication.filler_tolerance","value":"high"}}],"skippable":true,"meta_profiling":"Strong 'filler_hate' signal compounds with verbosity_preference minimal — double-flag for 'no outro lines' instruction.","dimension":"communication.filler_tolerance","why_this_matters":"Removes AI habits that are technically polite but feel hollow to you specifically."},{"id":"t1_q06","tier":1,"tier_name":"Communication DNA","question":"You ask a complex question. AI gives you the short answer first, then says 'want me to go deeper?' vs AI gives you the full breakdown immediately. Which do you prefer?","type":"scenario","options":[{"value":"short_first","label":"Short answer first, I'll ask for more if I want it","maps_to":{"dimension":"communication.depth_default","value":"brief_first"}},{"value":"full_breakdown","label":"Full breakdown immediately — I hate going back and forth","maps_to":{"dimension":"communication.depth_default","value":"full_upfront"}},{"value":"depends_question","label":"Depends on the type of question","maps_to":{"dimension":"communication.depth_default","value":"adaptive"}}],"skippable":true,"meta_profiling":null,"dimension":"communication.depth_default","why_this_matters":"AI learns whether to give you the headline or the whole story by default."},{"id":"t1_q07","tier":1,"tier_name":"Communication DNA","question":"You've just done something — shipped a project, finished a hard task. AI says 'Great job, you should be really proud!' Your reaction?","type":"scenario","options":[{"value":"cringe","label":"Cringe. Skip the cheerleading, please.","maps_to":{"dimension":"communication.praise_tolerance","value":"none"}},{"value":"neutral_prefer","label":"Neutral acknowledgment is fine, excessive praise isn't","maps_to":{"dimension":"communication.praise_tolerance","value":"neutral"}},{"value":"actually_nice","label":"Honestly? I don't mind it. Feels encouraging.","maps_to":{"dimension":"communication.praise_tolerance","value":"welcome"}},{"value":"love_it","label":"Give me ALL the affirmations","maps_to":{"dimension":"communication.praise_tolerance","value":"high"}}],"skippable":true,"meta_profiling":"Cross-reference with validation_need in Tier 4. If high validation need but 'cringe' here — note the contradiction: wants acknowledgment but from peers not tools.","dimension":"communication.praise_tolerance","why_this_matters":"AI knows whether to celebrate with you or just acknowledge and move on."},{"id":"t1_q08","tier":1,"tier_name":"Communication DNA","question":"Humor in AI conversations — where do you sit?","type":"select","options":[{"value":"no_humor","label":"Professional mode only — keep it focused","maps_to":{"dimension":"communication.humor","value":"none"}},{"value":"dry_wit","label":"Dry wit or clever observations — yes please","maps_to":{"dimension":"communication.humor","value":"dry"}},{"value":"light_humor","label":"Light humor here and there — keeps things enjoyable","maps_to":{"dimension":"communication.humor","value":"light"}},{"value":"bring_it","label":"Full personality — I want AI to actually be fun","maps_to":{"dimension":"communication.humor","value":"high"}}],"skippable":true,"meta_profiling":"If they write a funny answer themselves — validate high humor preference even if stated 'none'.","dimension":"communication.humor","why_this_matters":"Calibrates AI personality from strict assistant to genuinely enjoyable collaborator."},{"id":"t1_q09","tier":1,"tier_name":"Communication DNA","question":"You show AI your work and ask for feedback. You want it to...","type":"scenario","options":[{"value":"brutal","label":"Be brutal — I don't need hand-holding, I need the truth","maps_to":{"dimension":"communication.feedback_style","value":"critical_first"},"also_maps_to":{"dimension":"communication.directness","value":"direct"}},{"value":"balanced_direct","label":"Honest and direct — what's broken and how to fix it","maps_to":{"dimension":"communication.feedback_style","value":"direct_balanced"}},{"value":"sandwich","label":"The full picture — what works, what doesn't, specific improvements","maps_to":{"dimension":"communication.feedback_style","value":"comprehensive"}},{"value":"led_in","label":"Lead with what's good first, then the improvements","maps_to":{"dimension":"communication.feedback_style","value":"positive_first"}}],"skippable":false,"meta_profiling":"Feedback style preference is one of the highest-signal dimensions for cross-domain AI use. Note this carefully. First choice speed = confidence in preference.","dimension":"communication.feedback_style","why_this_matters":"How AI approaches anything you share for review — writing, code, ideas, plans."},{"id":"t1_q10","tier":1,"tier_name":"Communication DNA","question":"You're asking about something technical you half-know. AI uses precise technical jargon vs everyday language. Your preference?","type":"scenario","options":[{"value":"full_jargon","label":"Hit me with proper terminology — I can look up what I don't know","maps_to":{"dimension":"communication.jargon_preference","value":"expert"}},{"value":"jargon_explained","label":"Use the right terms but explain them if obscure","maps_to":{"dimension":"communication.jargon_preference","value":"semi_expert"}},{"value":"plain_language","label":"Plain language please — translate the jargon for me","maps_to":{"dimension":"communication.jargon_preference","value":"plain"}},{"value":"analogies","label":"Analogies and examples — make it concrete","maps_to":{"dimension":"communication.jargon_preference","value":"analogies"}}],"skippable":true,"meta_profiling":"Compare with tech_comfort from Tier 0. Mismatches (low tech comfort + 'full jargon') may indicate domain expertise in non-technical fields. Note for domain-specific adaptation.","dimension":"communication.jargon_preference","why_this_matters":"AI calibrates vocabulary to your level — no oversimplification, no unexplained acronyms."},{"id":"t1_q11","tier":1,"tier_name":"Communication DNA","question":"AI is working through something complex and explains its reasoning step-by-step as it goes. You...","type":"scenario","options":[{"value":"love_the_transparency","label":"Love it — I want to follow the logic, not just get the conclusion","maps_to":{"dimension":"communication.reasoning_visibility","value":"show_all"}},{"value":"summary_only","label":"Just show me the conclusion — hide the working","maps_to":{"dimension":"communication.reasoning_visibility","value":"conclusion_only"}},{"value":"key_steps","label":"Show me the key decision points, skip the obvious steps","maps_to":{"dimension":"communication.reasoning_visibility","value":"highlights_only"}},{"value":"depends_stakes","label":"For important decisions yes, for quick tasks no","maps_to":{"dimension":"communication.reasoning_visibility","value":"stakes_dependent"}}],"skippable":true,"meta_profiling":"Thinking-aloud preference separates people who want AI as a transparent collaborator from those who want a clean results machine. High interest in reasoning often correlates with analytical decision style.","dimension":"communication.reasoning_visibility","why_this_matters":"Sets whether AI shows its work or just delivers the answer."},{"id":"t1_q12","tier":1,"tier_name":"Communication DNA","question":"AI says 'This might work, but I'm not 100% certain' vs AI says 'Do this.' When the answer is genuinely uncertain, you prefer...","type":"scenario","options":[{"value":"always_hedge","label":"Always flag uncertainty — I'd rather know than get false confidence","maps_to":{"dimension":"communication.hedging_tolerance","value":"prefers_hedged"}},{"value":"confident_anyway","label":"Give me a confident answer even if uncertain — I'll verify what matters","maps_to":{"dimension":"communication.hedging_tolerance","value":"confident_preferred"}},{"value":"hedge_for_high_stakes","label":"Flag it only when the stakes are high — low stakes, just answer","maps_to":{"dimension":"communication.hedging_tolerance","value":"selective_hedging"}},{"value":"give_options","label":"Don't hedge — give me 2 options and let me pick","maps_to":{"dimension":"communication.hedging_tolerance","value":"options_over_hedging"}}],"skippable":true,"meta_profiling":"Hedging tolerance is a trust-calibration dimension. Someone who hates hedging may actually be building blind trust — note. Someone who demands hedging in all cases may have been burned before.","dimension":"communication.hedging_tolerance","why_this_matters":"Determines how AI communicates its own uncertainty — whether to say 'probably' or just commit."},{"id":"t1_q13","tier":1,"tier_name":"Communication DNA","question":"AI is about to tell you something you might not want to hear. You'd prefer it...","type":"scenario","options":[{"value":"straight_up","label":"Just say it. Straight up, no padding.","maps_to":{"dimension":"communication.difficult_message_delivery","value":"direct"}},{"value":"context_first","label":"Give me context so I understand WHY before the verdict","maps_to":{"dimension":"communication.difficult_message_delivery","value":"context_first"}},{"value":"acknowledge_intent","label":"Acknowledge what I was going for first, then the reality","maps_to":{"dimension":"communication.difficult_message_delivery","value":"empathic_then_honest"}},{"value":"with_path_forward","label":"Lead with the problem and immediately give me a path forward","maps_to":{"dimension":"communication.difficult_message_delivery","value":"problem_plus_solution"}}],"skippable":true,"meta_profiling":"Cross-reference with directness preference (t1_q02) and feedback_style (t1_q09). Consistent 'direct' across all three = very high directness. Inconsistent = context-sensitive.","dimension":"communication.difficult_message_delivery","why_this_matters":"Shapes how AI handles hard truths — when your idea has a flaw, when a plan won't work."},{"id":"t1_q14","tier":1,"tier_name":"Communication DNA","question":"Do you ever switch between languages mid-conversation? (like writing in one language but dropping terms from another)","type":"select","options":[{"value":"yes_frequently","label":"Yes — I naturally mix languages, AI should follow along","maps_to":{"dimension":"communication.code_switching","value":"high"},"triggers":["t1_q14a"]},{"value":"yes_technical","label":"Sometimes — mostly technical terms stay in English even if I write in another language","maps_to":{"dimension":"communication.code_switching","value":"technical_only"}},{"value":"no_one_language","label":"No — I stick to one language per conversation","maps_to":{"dimension":"communication.code_switching","value":"none"}}],"skippable":true,"meta_profiling":"If language from Tier 0 is non-English but answer here is 'technical_only' — note bilingual pattern for export: respond in native language, keep technical terms in English.","dimension":"communication.code_switching","why_this_matters":"AI can mirror your natural multilingual flow instead of staying rigidly in one language."},{"id":"t1_q14a","tier":1,"tier_name":"Communication DNA","question":"Which languages do you typically mix?","type":"open_text","placeholder":"e.g. Polish + English, Spanish + Portuguese...","skippable":true,"is_followup":true,"parent_question":"t1_q14","meta_profiling":null,"dimension":"communication.languages_mixed","why_this_matters":null},{"id":"t1_q15","tier":1,"tier_name":"Communication DNA","question":"You receive a message where the tone is playfully sarcastic: 'Oh sure, that'll definitely work perfectly.' Your immediate read?","type":"scenario","options":[{"value":"catch_it","label":"Got it immediately — sarcasm is clear to me in text","maps_to":{"dimension":"communication.sarcasm_comprehension","value":"high"}},{"value":"usually_get_it","label":"Usually catch it, but sometimes I need a moment","maps_to":{"dimension":"communication.sarcasm_comprehension","value":"moderate"}},{"value":"often_miss","label":"Honestly? I sometimes take it literally, especially in text","maps_to":{"dimension":"communication.sarcasm_comprehension","value":"low"}},{"value":"hate_it","label":"I get it, but I find sarcasm in text annoying — be direct","maps_to":{"dimension":"communication.sarcasm_comprehension","value":"dislikes"}}],"skippable":true,"meta_profiling":"Low sarcasm comprehension = AI should avoid ironic or sarcastic framing entirely. Dislikes = same outcome. High + humor preference = AI can use gentle sarcasm.","dimension":"communication.sarcasm_comprehension","why_this_matters":"Prevents AI from being accidentally confusing or condescending through tone that doesn't land in text."},{"id":"t1_q16","tier":1,"tier_name":"Communication DNA","question":"AI remembers something you mentioned in passing three weeks ago and brings it up now. You feel...","type":"scenario","options":[{"value":"impressed","label":"Impressed — that's exactly the kind of continuity I want","maps_to":{"dimension":"communication.memory_appreciation","value":"high"}},{"value":"slightly_unsettled","label":"Slightly unsettled — I forgot I said that","maps_to":{"dimension":"communication.memory_appreciation","value":"cautious"}},{"value":"depends_context","label":"Depends what it was — relevant = great, random = weird","maps_to":{"dimension":"communication.memory_appreciation","value":"contextual"}},{"value":"prefer_clean_slate","label":"I'd rather start fresh each time — don't accumulate stuff about me","maps_to":{"dimension":"communication.memory_appreciation","value":"minimal"}}],"skippable":true,"meta_profiling":"Memory appreciation signals privacy comfort level and desire for continuity. Cautious or minimal = AI should not surface old details without clear relevance. High = AI should proactively connect threads.","dimension":"communication.memory_appreciation","why_this_matters":"Sets how aggressively AI cross-references things you've shared in the past."},{"id":"t1_q17","tier":1,"tier_name":"Communication DNA","question":"When you're in the middle of explaining something and AI jumps in with an answer before you've finished — you feel:","type":"scenario","options":[{"value":"interrupted","label":"Annoyed — I wasn't done. Let me finish my thought.","maps_to":{"dimension":"communication.interruption_tolerance","value":"low"}},{"value":"efficient","label":"Fine actually — if it got the gist, time saved","maps_to":{"dimension":"communication.interruption_tolerance","value":"high"}},{"value":"depends_accuracy","label":"Fine if it got it right, annoying if it misunderstood","maps_to":{"dimension":"communication.interruption_tolerance","value":"accuracy_conditional"}}],"skippable":true,"meta_profiling":null,"dimension":"communication.interruption_tolerance","why_this_matters":"Shapes whether AI completes your thought or waits for full context before responding."},{"id":"t1_q18","tier":1,"tier_name":"Communication DNA","is_conditional":true,"show_if":{"tier0.professional_role":"developer"},"question":"You're reviewing code that someone else wrote. Comments in the code — your preference?","type":"select","options":[{"value":"self_documenting","label":"Clean code shouldn't need comments — names should explain everything","maps_to":{"dimension":"communication.code_comment_style","value":"minimal"}},{"value":"explain_why","label":"Comment the WHY not the WHAT — I can read the code","maps_to":{"dimension":"communication.code_comment_style","value":"why_only"}},{"value":"thorough","label":"Thorough comments — good for onboarding and future me","maps_to":{"dimension":"communication.code_comment_style","value":"thorough"}},{"value":"context_dependent","label":"Depends on complexity — obvious code = none, tricky logic = comment","maps_to":{"dimension":"communication.code_comment_style","value":"adaptive"}}],"skippable":true,"meta_profiling":"Code comment style is a proxy for documentation philosophy generally. Thorough comments = likely same person who likes detailed AI explanations.","dimension":"communication.code_comment_style","why_this_matters":"AI matches your documentation philosophy when generating or reviewing code."}]`),i={tier:_,tier_name:g,tier_intro:y,tier_complete:v,questions:f},b=2,w="Cognitive Profile",k="How does your brain actually work? Not personality — the mechanics. How you process information, make decisions, handle complexity, and learn. AI that understands HOW you think is a different tool than one that just adjusts its tone. 4-6 minutes.",I={headline:"Cognitive profile mapped.",body:"AI now knows how you process information, handle decisions, and deal with complexity. This is the layer most AI tools completely ignore. It's what separates 'helpful assistant' from 'thinking partner'. Next: how you work and get things done."},q=JSON.parse(`[{"id":"t2_q01","tier":2,"tier_name":"Cognitive Profile","question":"New gadget arrives — no instructions in the box. Your move?","type":"scenario","options":[{"value":"try_it_first","label":"Pick it up and start pressing buttons — I'll figure it out","maps_to":{"dimension":"cognitive.learning_style","value":"experiential"}},{"value":"quick_scan","label":"Quick scan of the manual for the key things, then wing it","maps_to":{"dimension":"cognitive.learning_style","value":"overview_first"}},{"value":"read_first","label":"Read the manual properly before touching anything","maps_to":{"dimension":"cognitive.learning_style","value":"structured_first"}},{"value":"watch_someone","label":"Find a YouTube video of someone using it — visual walkthrough","maps_to":{"dimension":"cognitive.learning_style","value":"observational"}}],"skippable":false,"meta_profiling":"Learning style affects how AI should structure explanations — overview-then-detail vs example-first vs step-by-step. This is a foundational cognitive dimension.","dimension":"cognitive.learning_style","why_this_matters":"AI structures every explanation to match how your brain absorbs new information."},{"id":"t2_q02","tier":2,"tier_name":"Cognitive Profile","question":"Big purchase decision — new laptop, a course, moving apartments. Your natural process?","type":"scenario","options":[{"value":"gut_check","label":"Gut feeling first — I gather data to confirm or challenge it","maps_to":{"dimension":"cognitive.decision_style","value":"intuitive"}},{"value":"systematic","label":"List everything out, weigh pros and cons, decide analytically","maps_to":{"dimension":"cognitive.decision_style","value":"analytical"}},{"value":"consult_others","label":"Talk it through with someone — I think out loud","maps_to":{"dimension":"cognitive.decision_style","value":"collaborative"}},{"value":"sleep_on_it","label":"Let it percolate — I come back 24 hours later with clarity","maps_to":{"dimension":"cognitive.decision_style","value":"incubation"}}],"skippable":false,"meta_profiling":"Decision style affects how AI should frame recommendations — as data to weigh vs clear verdict vs questions to think through. High-signal dimension.","dimension":"cognitive.decision_style","why_this_matters":"AI knows whether to give you a spreadsheet of pros/cons or a bold recommendation to react to."},{"id":"t2_q02a","tier":2,"tier_name":"Cognitive Profile","question":"When you're paralyzed between two options, what actually breaks the deadlock?","type":"select","is_followup":true,"parent_question":"t2_q02","options":[{"value":"ask_someone","label":"Someone I trust gives their opinion","maps_to":{"dimension":"cognitive.decision_unblock","value":"external_opinion"}},{"value":"deadline","label":"Deadline pressure — I just have to decide","maps_to":{"dimension":"cognitive.decision_unblock","value":"deadline"}},{"value":"coin_flip","label":"I flip a coin and check how I feel about the result","maps_to":{"dimension":"cognitive.decision_unblock","value":"gut_reveal"}},{"value":"more_data","label":"One more piece of information tips the scales","maps_to":{"dimension":"cognitive.decision_unblock","value":"data"}}],"skippable":true,"meta_profiling":null,"dimension":"cognitive.decision_unblock","why_this_matters":null},{"id":"t2_q03","tier":2,"tier_name":"Cognitive Profile","question":"Explaining gravity to a 10-year-old — you'd naturally start with...","type":"scenario","options":[{"value":"analogy","label":"An analogy — 'imagine the Earth is a bowling ball on a trampoline'","maps_to":{"dimension":"cognitive.abstraction_preference","value":"concrete"}},{"value":"question","label":"A question — 'why do you think you fall when you jump?'","maps_to":{"dimension":"cognitive.abstraction_preference","value":"socratic"}},{"value":"experiment","label":"Drop something — show it, then explain it","maps_to":{"dimension":"cognitive.abstraction_preference","value":"demonstration_first"}},{"value":"definition","label":"The principle — 'gravity is a force between masses'","maps_to":{"dimension":"cognitive.abstraction_preference","value":"abstract_first"}}],"skippable":true,"meta_profiling":"Abstraction level affects how AI explains anything new — from technical architecture to business strategy. Note if this contradicts learning_style preference.","dimension":"cognitive.abstraction_preference","why_this_matters":"AI chooses the right altitude for explanations — sky view or ground level, based on how your brain wires things together."},{"id":"t2_q04","tier":2,"tier_name":"Cognitive Profile","question":"Reading a long article or textbook chapter. Your actual approach?","type":"scenario","options":[{"value":"start_to_finish","label":"Start to finish, word by word — I process linearly","maps_to":{"dimension":"cognitive.information_processing","value":"linear"}},{"value":"skim_then_dive","label":"Skim headers and summary first, then dive where it seems worth it","maps_to":{"dimension":"cognitive.information_processing","value":"overview_first"}},{"value":"highlight_and_notes","label":"Read actively — highlight, annotate, make connections as I go","maps_to":{"dimension":"cognitive.information_processing","value":"active_annotator"}},{"value":"read_once_absorb","label":"Read once and let it absorb — I don't reread, I just synthesize as I go","maps_to":{"dimension":"cognitive.information_processing","value":"single_pass"}}],"skippable":true,"meta_profiling":"Information processing style affects how AI should present long content — summaries first, structured sections, or flowing prose.","dimension":"cognitive.information_processing","why_this_matters":"AI knows whether to give you the structured breakdown or the flowing narrative."},{"id":"t2_q05","tier":2,"tier_name":"Cognitive Profile","question":"You walk into a room where you've been before. Someone moved one item. Do you notice?","type":"scenario","options":[{"value":"immediately","label":"Yes immediately — something feels off before I can name it","maps_to":{"dimension":"cognitive.detail_orientation","value":"high"}},{"value":"eventually","label":"Usually — I'd notice within a minute if paying attention","maps_to":{"dimension":"cognitive.detail_orientation","value":"moderate"}},{"value":"rarely","label":"Probably not unless it was obvious — I focus on the big picture","maps_to":{"dimension":"cognitive.detail_orientation","value":"low"}},{"value":"depends_interest","label":"Depends if I care about that space — interest gates attention","maps_to":{"dimension":"cognitive.detail_orientation","value":"interest_gated"}}],"skippable":true,"meta_profiling":"Detail orientation affects whether AI should spell out every step vs assume the user will fill gaps. High detail = flag every edge case. Low = just hit the main points.","dimension":"cognitive.detail_orientation","why_this_matters":"AI calibrates how exhaustive to be — every caveat vs just the critical ones."},{"id":"t2_q06","tier":2,"tier_name":"Cognitive Profile","question":"Something breaks — app crash, unexpected result, plan falling apart. Your first instinct?","type":"scenario","options":[{"value":"diagnose_systematically","label":"What changed last? I trace back systematically to find the cause","maps_to":{"dimension":"cognitive.problem_solving","value":"deductive"}},{"value":"try_things","label":"Start trying fixes — trial and error is faster than theorizing","maps_to":{"dimension":"cognitive.problem_solving","value":"experimental"}},{"value":"reframe","label":"Zoom out and question the framing — maybe I'm solving the wrong problem","maps_to":{"dimension":"cognitive.problem_solving","value":"reframer"}},{"value":"research_first","label":"Research time — someone has solved this before","maps_to":{"dimension":"cognitive.problem_solving","value":"research_first"}}],"skippable":false,"meta_profiling":"Problem-solving style affects AI collaboration style — should AI ask questions to help reframe or provide solutions directly? Reframer is high-value; they often find the right problem.","dimension":"cognitive.problem_solving","why_this_matters":"AI adapts: questioning partner vs solution provider vs research assistant."},{"id":"t2_q07","tier":2,"tier_name":"Cognitive Profile","question":"Someone explains databases using a library analogy — 'tables are like bookshelves, rows are like books.' Your reaction?","type":"scenario","options":[{"value":"clicks_immediately","label":"Clicks immediately — analogies are how I build new mental models","maps_to":{"dimension":"cognitive.analogy_appreciation","value":"high"}},{"value":"helpful_but_not_necessary","label":"Helpful starting point, but I need to move past it to really understand","maps_to":{"dimension":"cognitive.analogy_appreciation","value":"scaffolding"}},{"value":"prefer_technical","label":"I'd rather just get the technical definition — analogies can mislead","maps_to":{"dimension":"cognitive.analogy_appreciation","value":"low"}},{"value":"depends_analogy","label":"Depends on the analogy — good ones help, bad ones confuse","maps_to":{"dimension":"cognitive.analogy_appreciation","value":"quality_dependent"}}],"skippable":true,"meta_profiling":"Analogy appreciation is closely related to abstraction preference. High analogy + concrete abstraction = powerful signal for example-first teaching. Low analogy + abstract preference = first principles learner.","dimension":"cognitive.analogy_appreciation","why_this_matters":"AI decides whether to reach for a concrete analogy or go straight to the actual concept."},{"id":"t2_q08","tier":2,"tier_name":"Cognitive Profile","question":"How do you picture something complex in your head — say, how a company or a codebase is organized?","type":"scenario","options":[{"value":"visual_spatial","label":"Visually — I see boxes, flows, maps. I'd draw it to understand it.","maps_to":{"dimension":"cognitive.mental_model","value":"visual_spatial"}},{"value":"narrative","label":"As a story — who does what, what happens when, cause and effect","maps_to":{"dimension":"cognitive.mental_model","value":"narrative"}},{"value":"hierarchical","label":"As a hierarchy — what's on top, what reports to what","maps_to":{"dimension":"cognitive.mental_model","value":"hierarchical"}},{"value":"rules_principles","label":"As rules and constraints — what can and can't happen","maps_to":{"dimension":"cognitive.mental_model","value":"rule_based"}}],"skippable":true,"meta_profiling":"Mental model type affects how AI should present complex systems. Visual = use diagrams and spatial language. Narrative = chronological story. Hierarchical = nested outlines. Rule-based = constraints and conditions.","dimension":"cognitive.mental_model","why_this_matters":"AI presents complex information in the spatial structure your brain naturally builds."},{"id":"t2_q09","tier":2,"tier_name":"Cognitive Profile","question":"AI drops a 2000-word answer to a question you asked. Your honest first reaction?","type":"scenario","options":[{"value":"scan_for_answer","label":"Scan for the key sentence and stop reading","maps_to":{"dimension":"cognitive.cognitive_load","value":"low_tolerance"}},{"value":"overwhelmed","label":"Overwhelmed — I won't absorb this and I know it","maps_to":{"dimension":"cognitive.cognitive_load","value":"very_low_tolerance"}},{"value":"read_if_needed","label":"Read it if the topic warrants — I can handle depth when it matters","maps_to":{"dimension":"cognitive.cognitive_load","value":"moderate"}},{"value":"appreciate_depth","label":"Appreciate it — I'd rather have too much and skim than need to ask again","maps_to":{"dimension":"cognitive.cognitive_load","value":"high_tolerance"}}],"skippable":true,"meta_profiling":"Cognitive load tolerance cross-references with verbosity preference. Inconsistency (want verbose but low tolerance) = wants depth available but not forced to read it all. Note the distinction.","dimension":"cognitive.cognitive_load","why_this_matters":"AI respects your actual reading capacity — especially for complex topics where depth is tempting."},{"id":"t2_q10","tier":2,"tier_name":"Cognitive Profile","question":"Client gives you a vague brief: 'Make it feel more premium.' No further spec. You:","type":"scenario","options":[{"value":"dive_in_interpret","label":"Dive in with my best interpretation — easier to react to something real","maps_to":{"dimension":"cognitive.ambiguity_tolerance","value":"high"}},{"value":"ask_one_question","label":"Ask one clarifying question, then proceed","maps_to":{"dimension":"cognitive.ambiguity_tolerance","value":"moderate"}},{"value":"need_more_spec","label":"Can't start without clearer requirements — vague = wasted work","maps_to":{"dimension":"cognitive.ambiguity_tolerance","value":"low"},"triggers":["t2_q10a"]},{"value":"explore_with_options","label":"Produce 2-3 interpretations and let them pick","maps_to":{"dimension":"cognitive.ambiguity_tolerance","value":"option_generator"}}],"skippable":true,"meta_profiling":"Ambiguity tolerance is extremely relevant to AI interaction — ambiguous prompts are the norm. Low tolerance = AI should always confirm its interpretation before proceeding.","dimension":"cognitive.ambiguity_tolerance","why_this_matters":"AI knows whether to proceed with its best guess or confirm interpretation before acting."},{"id":"t2_q10a","tier":2,"tier_name":"Cognitive Profile","question":"What's the minimum spec AI needs before you want it to proceed on ambiguous tasks?","type":"select","is_followup":true,"parent_question":"t2_q10","options":[{"value":"confirm_interpretation","label":"State its interpretation and ask me to confirm","maps_to":{"dimension":"cognitive.ambiguity_resolution","value":"confirm_first"}},{"value":"ask_one","label":"Ask me one clarifying question","maps_to":{"dimension":"cognitive.ambiguity_resolution","value":"single_question"}},{"value":"define_terms","label":"Define the key terms it's assuming","maps_to":{"dimension":"cognitive.ambiguity_resolution","value":"define_assumptions"}}],"skippable":true,"meta_profiling":null,"dimension":"cognitive.ambiguity_resolution","why_this_matters":null},{"id":"t2_q11","tier":2,"tier_name":"Cognitive Profile","question":"Your friend says 'write a happy birthday message for Alex — keep it short.' You...","type":"scenario","options":[{"value":"one_solid","label":"Write one great one — if it's good, why give options?","maps_to":{"dimension":"cognitive.creativity_expression","value":"quality_over_quantity"}},{"value":"few_options","label":"Write 3 different versions so they can choose the vibe","maps_to":{"dimension":"cognitive.creativity_expression","value":"options_generator"}},{"value":"ask_about_alex","label":"Ask a few things about Alex first — a generic message feels lazy","maps_to":{"dimension":"cognitive.creativity_expression","value":"context_first"}},{"value":"riff_freely","label":"Go a bit unexpected — funny, weird, memorable instead of the usual","maps_to":{"dimension":"cognitive.creativity_expression","value":"original_over_safe"}}],"skippable":true,"meta_profiling":"Creativity expression reveals how user prefers AI to handle open-ended tasks. Options-generator mindset = AI should always offer variants. Quality-over-quantity = one strong response preferred.","dimension":"cognitive.creativity_expression","why_this_matters":"AI learns whether to give you one polished output or a range to react to."},{"id":"t2_q12","tier":2,"tier_name":"Cognitive Profile","question":"You realize you've been completely wrong about something for years. Your honest internal reaction?","type":"scenario","options":[{"value":"update_fast_curious","label":"Fascinating — I love finding out I had it wrong. Good data.","maps_to":{"dimension":"cognitive.metacognition","value":"high_curious"},"also_maps_to":{"dimension":"personality.openness","value":"high"}},{"value":"update_uncomfortable","label":"A bit unsettling but I update — I can't stay wrong on purpose","maps_to":{"dimension":"cognitive.metacognition","value":"moderate"},"also_maps_to":{"dimension":"personality.openness","value":"resistant_then_open"}},{"value":"question_the_new","label":"Scrutinize the new information first — maybe I'm not wrong, maybe this is wrong","maps_to":{"dimension":"cognitive.metacognition","value":"skeptical_updater"},"also_maps_to":{"dimension":"personality.openness","value":"critical_update"}},{"value":"bothers_me","label":"Bothers me — I spend time figuring out how I got it so wrong","maps_to":{"dimension":"cognitive.metacognition","value":"self_analytical"},"also_maps_to":{"dimension":"personality.openness","value":"moderate"}}],"skippable":true,"meta_profiling":"Metacognition level is a proxy for intellectual honesty, self-awareness, AND openness to experience (Big Five O). High metacognition = AI can be more direct when the user is wrong, and can challenge assumptions aggressively. Skeptical updater = AI should provide strong evidence, not just assertions. Cross-reference with intellectual_challenge_appetite (t2_q14).","dimension":"cognitive.metacognition","secondary_dimension":"personality.openness","why_this_matters":"How AI calibrates its own directness when it has information that contradicts something you believe."},{"id":"t2_q13","tier":2,"tier_name":"Cognitive Profile","question":"You sit down to work on ONE important thing. Two hours later...","type":"scenario","options":[{"value":"done_or_deep","label":"Either I finished it or I'm three levels deeper than I planned — nothing in between","maps_to":{"dimension":"cognitive.attention_pattern","value":"hyperfocus_or_nothing"}},{"value":"steady_progress","label":"Steady, predictable progress — roughly where I expected to be","maps_to":{"dimension":"cognitive.attention_pattern","value":"consistent"}},{"value":"several_tabs","label":"Somehow on a different topic with 11 open tabs","maps_to":{"dimension":"cognitive.attention_pattern","value":"divergent_drift"},"triggers":["t2_q13a"]},{"value":"partial_progress","label":"Partial progress — I get things to 70% then mentally move on","maps_to":{"dimension":"cognitive.attention_pattern","value":"near_completion_gap"}}],"skippable":true,"meta_profiling":"Hyperfocus-or-nothing + divergent-drift are both ADHD-associated patterns. Note compound signals from t2_q06 (focus style) and t3_q14 (completion pattern). Don't label — just track.","dimension":"cognitive.attention_pattern","why_this_matters":"AI formats tasks and sessions to match how your attention actually behaves, not an idealized version of it."},{"id":"t2_q13a","tier":2,"tier_name":"Cognitive Profile","question":"When you drift off-task like that — is it usually because of the task or despite it?","type":"select","is_followup":true,"parent_question":"t2_q13","options":[{"value":"task_too_boring","label":"Task was boring — my brain found something more interesting","maps_to":{"dimension":"cognitive.drift_cause","value":"under_stimulation"}},{"value":"task_too_hard","label":"Task was hard with no clear entry — drifting felt easier","maps_to":{"dimension":"cognitive.drift_cause","value":"overwhelm_avoidance"}},{"value":"just_happens","label":"Just happens — I can be deep into something I love and still drift","maps_to":{"dimension":"cognitive.drift_cause","value":"involuntary"}}],"skippable":true,"meta_profiling":"Involuntary drift = stronger executive function flag. Note for Tier 5.","dimension":"cognitive.drift_cause","why_this_matters":null},{"id":"t2_q14","tier":2,"tier_name":"Cognitive Profile","question":"How do you feel about being challenged intellectually — when AI disagrees with your conclusion?","type":"scenario","options":[{"value":"love_it","label":"Bring it. If I'm wrong, I want to know. Don't coddle me.","maps_to":{"dimension":"cognitive.intellectual_challenge_appetite","value":"high"}},{"value":"welcome_if_earned","label":"Welcome it if AI has done its homework — not just contrarianism","maps_to":{"dimension":"cognitive.intellectual_challenge_appetite","value":"earned_pushback"}},{"value":"depends_domain","label":"In my domain, yes. Outside it, I'm more open to being guided.","maps_to":{"dimension":"cognitive.intellectual_challenge_appetite","value":"domain_conditional"}},{"value":"softer_please","label":"I'm open to it but prefer the disagreement framed as a question, not a correction","maps_to":{"dimension":"cognitive.intellectual_challenge_appetite","value":"gentle_challenge"}}],"skippable":true,"meta_profiling":"Cross-reference with feedback_style (t1_q09). If they want brutal feedback but soft intellectual challenges — note asymmetry: critical about work is fine, challenging beliefs is sensitive.","dimension":"cognitive.intellectual_challenge_appetite","why_this_matters":"Calibrates how AI handles moments when it thinks you're wrong — does it say so or ask questions?"},{"id":"t2_q15","tier":2,"tier_name":"Cognitive Profile","question":"When figuring out a hard problem, what role do you want AI to play?","type":"scenario","options":[{"value":"rubber_duck","label":"Just let me talk through it — you don't even need to answer, just listen","maps_to":{"dimension":"cognitive.ai_role_in_thinking","value":"sounding_board"}},{"value":"challenger","label":"Challenge my assumptions — ask the questions that poke holes","maps_to":{"dimension":"cognitive.ai_role_in_thinking","value":"devil_advocate"}},{"value":"solution_provider","label":"Just give me the answer — I don't need to think out loud","maps_to":{"dimension":"cognitive.ai_role_in_thinking","value":"answer_machine"}},{"value":"structured_guide","label":"Walk me through a structured process — help me think step by step","maps_to":{"dimension":"cognitive.ai_role_in_thinking","value":"structured_guide"}}],"skippable":false,"meta_profiling":"This is a fundamental AI relationship dimension. Sounding board = AI should confirm receipt and ask one probing question. Devil's advocate = AI should play adversarially. Answer machine = AI should be directive.","dimension":"cognitive.ai_role_in_thinking","why_this_matters":"Sets the default dynamic — are you thinking together or is AI answering your questions?"},{"id":"t2_q16","tier":2,"tier_name":"Cognitive Profile","question":"How comfortable are you with 'I'm not sure yet — let's figure it out together'?","type":"scenario","options":[{"value":"love_it","label":"That's actually my preferred mode — exploration over certainty","maps_to":{"dimension":"cognitive.uncertainty_tolerance","value":"high"}},{"value":"fine_with_it","label":"Fine, as long as we're making progress and not spinning","maps_to":{"dimension":"cognitive.uncertainty_tolerance","value":"moderate"}},{"value":"makes_me_anxious","label":"Makes me uncomfortable — I function better with clear answers","maps_to":{"dimension":"cognitive.uncertainty_tolerance","value":"low"},"triggers":["t2_q16a"]},{"value":"domain_specific","label":"Depends on stakes — low stakes = explore, high stakes = I need direction","maps_to":{"dimension":"cognitive.uncertainty_tolerance","value":"stakes_dependent"}}],"skippable":true,"meta_profiling":"Uncertainty tolerance affects whether AI should say 'here are the options' vs 'here's what I recommend'. Low tolerance = always give the recommendation even when uncertain.","dimension":"cognitive.uncertainty_tolerance","why_this_matters":"AI knows when to say 'probably' and explore with you vs when to give you a clear answer."},{"id":"t2_q16a","tier":2,"tier_name":"Cognitive Profile","question":"When AI is uncertain, what do you actually want it to do?","type":"select","is_followup":true,"parent_question":"t2_q16","options":[{"value":"best_guess","label":"Give me your best guess and label it as uncertain","maps_to":{"dimension":"cognitive.uncertainty_handling","value":"best_guess_labeled"}},{"value":"ask_clarifying","label":"Ask me a clarifying question to reduce uncertainty","maps_to":{"dimension":"cognitive.uncertainty_handling","value":"clarify_first"}},{"value":"give_options","label":"Give me 2-3 options depending on which assumption is right","maps_to":{"dimension":"cognitive.uncertainty_handling","value":"branching_answers"}}],"skippable":true,"meta_profiling":null,"dimension":"cognitive.uncertainty_handling","why_this_matters":null}]`),o={tier:b,tier_name:w,tier_intro:k,tier_complete:I,questions:q},x=3,A="Work & Productivity",j="This is where AI becomes a real productivity tool, not just a search engine. How you work, when you're sharp, what kills your flow, and how you actually get things done. No judgment — everyone's different. 5-7 minutes.",C={headline:"Work profile locked.",body:"AI now knows your energy rhythms, task patterns, and what actually gets you moving. Task management, scheduling, and project help just got a lot smarter. Next up: the deep personality layer — the most interesting tier."},P=JSON.parse(`[{"id":"t3_q01","tier":3,"tier_name":"Work & Productivity","question":"Your most productive day last week — describe it in one sentence. Which of these comes closest?","type":"scenario","options":[{"value":"sprinter","label":"Locked in for 4 hours, crushed a huge thing, then was done for the day","maps_to":{"dimension":"work.energy_archetype","value":"sprinter"}},{"value":"steady","label":"Consistent pace all day — no huge highs, just solid output","maps_to":{"dimension":"work.energy_archetype","value":"steady"}},{"value":"burst_rest","label":"On for 90 minutes, break, repeat — rhythm of focused bursts","maps_to":{"dimension":"work.energy_archetype","value":"burst_rest"}},{"value":"reactive","label":"Mostly reactive — handled what came up and did it well","maps_to":{"dimension":"work.energy_archetype","value":"reactive"}}],"skippable":false,"meta_profiling":"Energy archetype is a high-level signal that shapes task scheduling, session length recommendations, and workload advice across all AI interactions.","dimension":"work.energy_archetype","why_this_matters":"AI schedules recommendations and task pacing to match your natural weekly rhythm."},{"id":"t3_q02","tier":3,"tier_name":"Work & Productivity","question":"When during the day are you genuinely at your best — sharpest thinking, highest output?","type":"select","options":[{"value":"early_morning","label":"Early morning (6-9am) — brain is clearest before the world wakes up","maps_to":{"dimension":"work.peak_hours","value":"early_morning"}},{"value":"late_morning","label":"Mid-morning (9am-12pm)","maps_to":{"dimension":"work.peak_hours","value":"late_morning"}},{"value":"afternoon","label":"Afternoon (1pm-5pm)","maps_to":{"dimension":"work.peak_hours","value":"afternoon"}},{"value":"evening","label":"Evening (5pm-10pm) — I come alive later","maps_to":{"dimension":"work.peak_hours","value":"evening"}},{"value":"late_night","label":"Late night — when everything is quiet","maps_to":{"dimension":"work.peak_hours","value":"night_owl"}},{"value":"variable","label":"Varies by day — no consistent peak","maps_to":{"dimension":"work.peak_hours","value":"variable"}}],"skippable":true,"meta_profiling":null,"dimension":"work.peak_hours","why_this_matters":"AI suggests timing for tasks and knows when you're likely to be sharp vs winding down."},{"id":"t3_q03","tier":3,"tier_name":"Work & Productivity","question":"Before starting a big project, you...","type":"scenario","options":[{"value":"break_into_tasks","label":"Break it into every task I can think of before I touch anything","maps_to":{"dimension":"work.task_granularity","value":"front_loaded_planning"}},{"value":"rough_phases","label":"Sketch rough phases — enough to start, I'll detail as I go","maps_to":{"dimension":"work.task_granularity","value":"iterative_planning"}},{"value":"first_step_only","label":"Identify the first concrete step — planning too far ahead feels wasteful","maps_to":{"dimension":"work.task_granularity","value":"next_step_only"}},{"value":"just_start","label":"Just start — the plan reveals itself once you're inside it","maps_to":{"dimension":"work.task_granularity","value":"no_upfront_planning"}}],"skippable":true,"meta_profiling":"Task granularity determines how AI should present project breakdowns — full Gantt-style decomposition vs two-step next actions.","dimension":"work.task_granularity","why_this_matters":"AI generates task breakdowns at the depth you actually use, not an overwhelming 50-item list."},{"id":"t3_q04","tier":3,"tier_name":"Work & Productivity","question":"Your todo list typically covers...","type":"select","options":[{"value":"today_only","label":"Today — tomorrow will figure itself out","maps_to":{"dimension":"work.planning_horizon","value":"day"}},{"value":"this_week","label":"This week — I have a rough plan for the next 5 days","maps_to":{"dimension":"work.planning_horizon","value":"week"}},{"value":"this_month","label":"This month — I work in monthly sprints","maps_to":{"dimension":"work.planning_horizon","value":"month"}},{"value":"quarter","label":"Next quarter — I think in 90-day cycles","maps_to":{"dimension":"work.planning_horizon","value":"quarter"}},{"value":"year_or_more","label":"Year or more — I have a roadmap in my head","maps_to":{"dimension":"work.planning_horizon","value":"year_plus"}}],"skippable":true,"meta_profiling":null,"dimension":"work.planning_horizon","why_this_matters":"AI calibrates goal-setting and project suggestions to how far ahead you naturally think."},{"id":"t3_q05","tier":3,"tier_name":"Work & Productivity","question":"You have a deadline in 3 days and you haven't started. You're most likely to...","type":"scenario","options":[{"value":"deadline_driven","label":"Start today — this is normal for me. Deadline pressure is my fuel.","maps_to":{"dimension":"work.deadline_behavior","value":"deadline_driven"},"triggers":["t3_q05a"]},{"value":"structured_plan","label":"Break it into daily milestones and start immediately","maps_to":{"dimension":"work.deadline_behavior","value":"structured_planner"}},{"value":"stress_paralysis","label":"Feel the pressure but have trouble starting — then cram at the end","maps_to":{"dimension":"work.deadline_behavior","value":"stress_paralysis"},"triggers":["t3_q05b"]},{"value":"started_already","label":"I'd already be halfway done — I can't leave things to the last minute","maps_to":{"dimension":"work.deadline_behavior","value":"early_starter"}}],"skippable":false,"meta_profiling":"Deadline behavior is one of the most predictive work dimensions. Stress_paralysis pattern deserves a follow-up for initiation strategies.","dimension":"work.deadline_behavior","why_this_matters":"AI knows whether to front-load urgency or help you build structure to avoid last-minute crunches."},{"id":"t3_q05a","tier":3,"tier_name":"Work & Productivity","question":"When you're running on deadline pressure — quality outcome?","type":"select","is_followup":true,"parent_question":"t3_q05","options":[{"value":"great_results","label":"Often my best work — adrenaline sharpens me","maps_to":{"dimension":"work.deadline_quality","value":"improves_under_pressure"}},{"value":"good_enough","label":"Good enough, but I know I could do better with more time","maps_to":{"dimension":"work.deadline_quality","value":"adequate"}},{"value":"regret_it","label":"Usually wish I'd started earlier — quality takes a hit","maps_to":{"dimension":"work.deadline_quality","value":"degrades"}}],"skippable":true,"meta_profiling":null,"dimension":"work.deadline_quality","why_this_matters":null},{"id":"t3_q05b","tier":3,"tier_name":"Work & Productivity","question":"What helps you break out of that starting paralysis?","type":"select","is_followup":true,"parent_question":"t3_q05","options":[{"value":"someone_watching","label":"Having someone else around — body doubling works for me","maps_to":{"dimension":"work.initiation_aid","value":"body_doubling"}},{"value":"micro_task","label":"Breaking it into one tiny first step I can't say no to","maps_to":{"dimension":"work.initiation_aid","value":"micro_commitment"}},{"value":"environment_change","label":"Changing location — different space, different brain","maps_to":{"dimension":"work.initiation_aid","value":"environment_shift"}},{"value":"accountability","label":"Telling someone I'll have it done by X","maps_to":{"dimension":"work.initiation_aid","value":"public_commitment"}}],"skippable":true,"meta_profiling":"body_doubling is a strong ADHD-associated coping strategy. Note for Tier 5 flag.","dimension":"work.initiation_aid","why_this_matters":null},{"id":"t3_q06","tier":3,"tier_name":"Work & Productivity","question":"Your ideal work setup — choose the one that sounds best for actually getting things done:","type":"select","options":[{"value":"solo","label":"Solo, deep focus — no interruptions, full ownership","maps_to":{"dimension":"work.collaboration_preference","value":"independent"}},{"value":"async_team","label":"Async team — I like knowing others are involved, but on my schedule","maps_to":{"dimension":"work.collaboration_preference","value":"async_collaborative"}},{"value":"sync_pair","label":"Tight real-time pairing — working side by side with one person","maps_to":{"dimension":"work.collaboration_preference","value":"sync_pair"}},{"value":"team_energy","label":"Group energy — I'm better in a room with people working around me","maps_to":{"dimension":"work.collaboration_preference","value":"group_presence"}}],"skippable":true,"meta_profiling":null,"dimension":"work.collaboration_preference","why_this_matters":"AI adapts recommendations for solo workflows vs team coordination needs."},{"id":"t3_q07","tier":3,"tier_name":"Work & Productivity","question":"New productivity app — everyone's raving about it, Notion/Linear/Obsidian-level hype. Your instinct?","type":"scenario","options":[{"value":"try_it_immediately","label":"Try it immediately — I'm always looking for a better setup","maps_to":{"dimension":"work.tool_philosophy","value":"early_adopter"}},{"value":"read_reviews_first","label":"Read a few reviews, check if it actually solves a problem I have","maps_to":{"dimension":"work.tool_philosophy","value":"deliberate_adopter"}},{"value":"skeptical","label":"Skeptical — I've been burned by tool-switching overhead too many times","maps_to":{"dimension":"work.tool_philosophy","value":"conservative"}},{"value":"wait_and_see","label":"Wait 6 months — if it's still around and people still love it, then I'll look","maps_to":{"dimension":"work.tool_philosophy","value":"late_adopter"}}],"skippable":true,"meta_profiling":"Tool philosophy affects how AI recommends new tools and systems. Early adopter = mention promising tools. Conservative = only suggest when current tool clearly failing.","dimension":"work.tool_philosophy","why_this_matters":"AI knows whether to suggest new tools or help you get more out of what you already use."},{"id":"t3_q08","tier":3,"tier_name":"Work & Productivity","question":"After finishing a project, your notes and documentation look like...","type":"scenario","options":[{"value":"thorough_docs","label":"Thorough — I write things up properly so future-me doesn't suffer","maps_to":{"dimension":"work.documentation_habit","value":"high"}},{"value":"key_points","label":"Key points and lessons — enough to remember what mattered","maps_to":{"dimension":"work.documentation_habit","value":"minimal"}},{"value":"nothing","label":"Nothing — the work is done, I move on","maps_to":{"dimension":"work.documentation_habit","value":"low"}},{"value":"only_if_complex","label":"Only if it was complex enough to warrant it","maps_to":{"dimension":"work.documentation_habit","value":"selective"}}],"skippable":true,"meta_profiling":"Documentation habit affects whether AI should produce written outputs proactively (for low-doc users) or keep things in flowing conversation (for high-doc users who capture themselves).","dimension":"work.documentation_habit","why_this_matters":"AI knows whether to proactively produce summaries and notes or trust you to capture what matters."},{"id":"t3_q09","tier":3,"tier_name":"Work & Productivity","question":"You're deep in work, someone interrupts. You:","type":"scenario","options":[{"value":"devastating","label":"It takes me 20+ minutes to recover — interruptions are expensive for me","maps_to":{"dimension":"work.context_switching_cost","value":"very_high"}},{"value":"annoying_but_ok","label":"Annoying but I get back within 5 minutes","maps_to":{"dimension":"work.context_switching_cost","value":"moderate"}},{"value":"handles_well","label":"Handle it, write a quick note of where I was, resume","maps_to":{"dimension":"work.context_switching_cost","value":"low"}},{"value":"sometimes_welcome","label":"Sometimes welcome — a forced break can actually reset me","maps_to":{"dimension":"work.context_switching_cost","value":"variable"}}],"skippable":true,"meta_profiling":"Very high context-switching cost combined with hard-to-start patterns = executive function compound signal. Note for Tier 5 ADHD flag.","dimension":"work.context_switching_cost","why_this_matters":"AI knows whether to batch things before surfacing them or treat interruptions as acceptable."},{"id":"t3_q10","tier":3,"tier_name":"Work & Productivity","question":"You do the same 3-click thing every single day. AI could automate it in 10 minutes. You...","type":"scenario","options":[{"value":"automate_everything","label":"Automate it immediately — every repeated manual task is debt","maps_to":{"dimension":"work.automation_tendency","value":"high"}},{"value":"automate_if_worth_it","label":"Depends how complex the setup is vs time saved","maps_to":{"dimension":"work.automation_tendency","value":"roi_based"}},{"value":"keep_manual","label":"Keep it manual — automations break and then I'm stuck","maps_to":{"dimension":"work.automation_tendency","value":"low"}},{"value":"intend_never_do","label":"Intend to automate it but somehow never get around to it","maps_to":{"dimension":"work.automation_tendency","value":"aspirational_only"}}],"skippable":true,"meta_profiling":"Automation tendency reveals relationship with technical friction and long-term thinking. High automators value AI as infrastructure, not just assistant.","dimension":"work.automation_tendency","why_this_matters":"Determines whether AI should proactively suggest automation opportunities or focus on manual execution."},{"id":"t3_q11","tier":3,"tier_name":"Work & Productivity","question":"Plot your energy through a typical day. Which shape fits best?","type":"scenario","options":[{"value":"morning_peak_drop","label":"High in the morning, drops after lunch, recovers slightly evening","maps_to":{"dimension":"work.energy_curve","value":"morning_peak"}},{"value":"slow_build","label":"Slow start, builds through the day, peaks afternoon/evening","maps_to":{"dimension":"work.energy_curve","value":"slow_riser"}},{"value":"flat","label":"Relatively flat — consistent energy throughout","maps_to":{"dimension":"work.energy_curve","value":"flat"}},{"value":"spikes_variable","label":"Unpredictable spikes — I can't forecast when I'll be sharp","maps_to":{"dimension":"work.energy_curve","value":"variable_spikes"}}],"skippable":true,"meta_profiling":"Energy curve combined with peak_hours gives full daily profile. Variable spikes + unpredictable = adaptive scheduling needed rather than fixed blocks.","dimension":"work.energy_curve","why_this_matters":"AI matches task type to energy level — deep thinking work when sharp, admin when not."},{"id":"t3_q12","tier":3,"tier_name":"Work & Productivity","question":"2 hours into focused work. You need a break. Your ideal break looks like...","type":"scenario","options":[{"value":"complete_switch","label":"Complete mental switch — walk, gym, anything non-screen","maps_to":{"dimension":"work.break_pattern","value":"physical_reset"}},{"value":"low_intensity_screen","label":"Low-intensity screen — YouTube, social, something passive","maps_to":{"dimension":"work.break_pattern","value":"passive_screen"}},{"value":"short_and_back","label":"5 minutes max — just enough to reset, then back","maps_to":{"dimension":"work.break_pattern","value":"micro_break"}},{"value":"hard_to_stop","label":"I rarely take proper breaks — I either keep going or crash","maps_to":{"dimension":"work.break_pattern","value":"all_or_nothing"}}],"skippable":true,"meta_profiling":"All-or-nothing break pattern + burst-rest archetype = unsustainable cycle warning. Note without flagging to user.","dimension":"work.break_pattern","why_this_matters":"AI suggests break types that actually restore you vs ones that extend procrastination."},{"id":"t3_q13","tier":3,"tier_name":"Work & Productivity","question":"How do you actually keep track of what needs doing? (Be honest — your real system, not the ideal one)","type":"select","options":[{"value":"dedicated_app","label":"Dedicated task manager — Notion, Todoist, Linear, etc.","maps_to":{"dimension":"work.task_system","value":"dedicated_tool"}},{"value":"notes_app","label":"Notes app or document — Obsidian, Apple Notes, a running doc","maps_to":{"dimension":"work.task_system","value":"notes_based"}},{"value":"calendar","label":"Calendar — if it's not scheduled it doesn't exist","maps_to":{"dimension":"work.task_system","value":"calendar_based"}},{"value":"mental","label":"Mental list — it's all in my head and it mostly works","maps_to":{"dimension":"work.task_system","value":"mental"}},{"value":"nothing_consistent","label":"Nothing consistent — I'm looking for a better system","maps_to":{"dimension":"work.task_system","value":"no_system"}}],"skippable":true,"meta_profiling":"Mental-only task management + high task load = spill risk. Note for proactive reminders offer. Calendar-based = AI should suggest time-blocking.","dimension":"work.task_system","why_this_matters":"AI works with your existing system instead of trying to impose a new one."},{"id":"t3_q14","tier":3,"tier_name":"Work & Productivity","question":"Your ideal way to align with someone on something — a decision, a plan, a piece of work?","type":"select","options":[{"value":"async_doc","label":"Async — shared doc, comments, no meeting needed","maps_to":{"dimension":"work.meeting_preference","value":"async_preferred"}},{"value":"short_sync","label":"Short call or chat — 15 minutes sync beats 3 days of back-and-forth","maps_to":{"dimension":"work.meeting_preference","value":"short_sync"}},{"value":"long_deep_conversation","label":"Proper conversation — I think better in dialogue","maps_to":{"dimension":"work.meeting_preference","value":"deep_sync"}},{"value":"depends","label":"Depends on complexity — quick = async, strategic = sync","maps_to":{"dimension":"work.meeting_preference","value":"adaptive"}}],"skippable":true,"meta_profiling":null,"dimension":"work.meeting_preference","why_this_matters":"AI suggests the right communication mode for different types of collaboration."},{"id":"t3_q15","tier":3,"tier_name":"Work & Productivity","question":"You submit work. When do you want feedback?","type":"scenario","options":[{"value":"immediate","label":"Immediately — I'm still in context, fast feedback is most useful","maps_to":{"dimension":"work.feedback_loop","value":"immediate"}},{"value":"few_hours","label":"Few hours — give it time to breathe, then review","maps_to":{"dimension":"work.feedback_loop","value":"same_day"}},{"value":"when_ready","label":"Whenever the reviewer is ready — I'd rather have good feedback than fast","maps_to":{"dimension":"work.feedback_loop","value":"quality_over_speed"}},{"value":"iteration_based","label":"In rounds — quick initial reaction, then detailed when it's more developed","maps_to":{"dimension":"work.feedback_loop","value":"iterative"}}],"skippable":true,"meta_profiling":"Feedback loop preference affects how AI delivers reviews. Immediate = AI should always respond to shared work right away. Quality-over-speed = AI can take time to compose thorough feedback.","dimension":"work.feedback_loop","why_this_matters":"AI times feedback delivery to match when you're most receptive and still engaged."},{"id":"t3_q16","tier":3,"tier_name":"Work & Productivity","question":"The project is 90% done. You...","type":"scenario","options":[{"value":"ship_it","label":"Ship the 90% — done and imperfect beats perfect and delayed","maps_to":{"dimension":"work.completion_pattern","value":"pragmatic_shipper"}},{"value":"finish_properly","label":"Do the last 10% properly — 90% is not done","maps_to":{"dimension":"work.completion_pattern","value":"strong_completer"}},{"value":"lose_interest","label":"Lose momentum — the exciting parts are done, the last 10% drags","maps_to":{"dimension":"work.completion_pattern","value":"novelty_seeker"},"triggers":["t3_q16a"]},{"value":"perfectionism_kicks_in","label":"Keep finding things to improve — 90% becomes 95% becomes 'still not ready'","maps_to":{"dimension":"work.completion_pattern","value":"perfectionist"},"triggers":["t3_q16b"]}],"skippable":true,"meta_profiling":"novelty_seeker + perfectionist completion patterns are both common ADHD-adjacent patterns. Note compound with t4_q10 perfectionism and t2_q13 attention patterns.","dimension":"work.completion_pattern","why_this_matters":"AI knows how to help you actually ship — not just start."},{"id":"t3_q16a","tier":3,"tier_name":"Work & Productivity","question":"What's the best external lever to get you through that last 10%?","type":"select","is_followup":true,"parent_question":"t3_q16","options":[{"value":"deadline","label":"Hard deadline — make it real and I'll do it","maps_to":{"dimension":"work.completion_lever","value":"deadline"}},{"value":"audience","label":"Someone waiting for it — accountability to another person","maps_to":{"dimension":"work.completion_lever","value":"audience"}},{"value":"reframe_as_small","label":"Breaking the 10% into tiny steps — make the finish line visible","maps_to":{"dimension":"work.completion_lever","value":"micro_steps"}}],"skippable":true,"meta_profiling":null,"dimension":"work.completion_lever","why_this_matters":null},{"id":"t3_q16b","tier":3,"tier_name":"Work & Productivity","question":"How do you know when something is 'done enough' to ship?","type":"select","is_followup":true,"parent_question":"t3_q16","options":[{"value":"external_deadline","label":"Hard deadline forces my hand","maps_to":{"dimension":"work.done_criteria","value":"deadline_forced"}},{"value":"someone_else_says","label":"Someone else tells me it's good enough","maps_to":{"dimension":"work.done_criteria","value":"external_validation"}},{"value":"checklist","label":"I have a mental checklist — if it passes, it ships","maps_to":{"dimension":"work.done_criteria","value":"internal_checklist"}},{"value":"still_figuring_out","label":"Honestly still figuring this out","maps_to":{"dimension":"work.done_criteria","value":"undefined"}}],"skippable":true,"meta_profiling":null,"dimension":"work.done_criteria","why_this_matters":null},{"id":"t3_q17","tier":3,"tier_name":"Work & Productivity","question":"Your ideal work environment. What matters most?","type":"multi_select","instruction":"Pick up to 3","options":[{"value":"silence","label":"Quiet — low noise or silence","maps_to":{"dimension":"work.workspace","value":"silence"}},{"value":"music","label":"Music or ambient sound — specific type matters","maps_to":{"dimension":"work.workspace","value":"ambient_audio"}},{"value":"natural_light","label":"Natural light — windows, outdoors, daylight","maps_to":{"dimension":"work.workspace","value":"natural_light"}},{"value":"private","label":"Physical privacy — I can't think when people walk past me","maps_to":{"dimension":"work.workspace","value":"privacy"}},{"value":"visible_progress","label":"Visible progress — checklist, board, something that shows I'm moving","maps_to":{"dimension":"work.workspace","value":"visible_progress"}},{"value":"flexibility","label":"Flexibility — I rotate between locations, one spot kills me","maps_to":{"dimension":"work.workspace","value":"location_variety"}}],"max_selections":3,"skippable":true,"meta_profiling":"Workspace preferences are surprisingly stable personality indicators. Privacy + silence = introvert peak performance. Ambient audio + flexibility = stimulation-seeking.","dimension":"work.workspace","why_this_matters":"AI can recommend and describe optimal environments when you're planning focus sessions."},{"id":"t3_q18","tier":3,"tier_name":"Work & Productivity","question":"It's 8pm, you get a work message that could wait but you'd know about it. You...","type":"scenario","options":[{"value":"respond_immediately","label":"Respond immediately — it'll take 2 minutes and then it's done","maps_to":{"dimension":"work.work_life_boundary","value":"none"}},{"value":"read_then_decide","label":"Read it, decide if it's urgent, respond only if it is","maps_to":{"dimension":"work.work_life_boundary","value":"selective"}},{"value":"see_tomorrow","label":"See it tomorrow — evenings are my time","maps_to":{"dimension":"work.work_life_boundary","value":"strict"}},{"value":"depends_period","label":"Depends where I am in a project — crunch mode = always on, normal = off","maps_to":{"dimension":"work.work_life_boundary","value":"project_dependent"}}],"skippable":true,"meta_profiling":"Work-life boundary is both a preference and a health signal. No boundary + high work intensity = burnout risk indicator. Note for long-term pacing recommendations.","dimension":"work.work_life_boundary","why_this_matters":"AI respects your boundaries around personal time — or helps you build them if you want that."},{"id":"t3_q19","tier":3,"tier_name":"Work & Productivity","question":"When AI helps you with a task, which mode feels most natural?","type":"scenario","options":[{"value":"tell_me_what_to_do","label":"Tell me the steps and I'll execute — just give me the playbook","maps_to":{"dimension":"work.ai_assistance_mode","value":"directive_execution"}},{"value":"do_it_together","label":"Work through it together — I want to be involved in the thinking","maps_to":{"dimension":"work.ai_assistance_mode","value":"collaborative"}},{"value":"you_do_it","label":"Draft a complete output and I'll review and edit","maps_to":{"dimension":"work.ai_assistance_mode","value":"ai_first_human_reviews"}},{"value":"give_me_options","label":"Give me options and I'll pick and refine","maps_to":{"dimension":"work.ai_assistance_mode","value":"options_then_refine"}}],"skippable":false,"meta_profiling":"Strongest single indicator for AI collaboration style. ai_first_human_reviews = high delegation comfort. collaborative = AI as thinking partner not tool.","dimension":"work.ai_assistance_mode","why_this_matters":"Sets the fundamental dynamic of how you and AI divide labor."},{"id":"t3_q20","tier":3,"tier_name":"Work & Productivity","question":"You've been sitting on a task for a week without starting. The real reason is usually...","type":"scenario","options":[{"value":"not_clear_enough","label":"Not clear enough — I don't know exactly what 'done' looks like","maps_to":{"dimension":"work.procrastination_driver","value":"ambiguity"}},{"value":"feels_overwhelming","label":"It feels too big — I don't know where to start","maps_to":{"dimension":"work.procrastination_driver","value":"overwhelm"}},{"value":"not_interesting","label":"It's boring and I keep finding more interesting things","maps_to":{"dimension":"work.procrastination_driver","value":"boredom"}},{"value":"fear_of_bad_result","label":"Fear of doing it wrong — I put it off because I might fail","maps_to":{"dimension":"work.procrastination_driver","value":"performance_anxiety"}},{"value":"external_dependency","label":"Waiting on something or someone else — not fully in my control","maps_to":{"dimension":"work.procrastination_driver","value":"external_block"}}],"skippable":true,"meta_profiling":"Procrastination driver is the most actionable dimension for AI to address. Overwhelm = smaller steps. Ambiguity = clearer definition. Boredom = gamification. Performance anxiety = lower stakes framing.","dimension":"work.procrastination_driver","why_this_matters":"AI addresses the real reason tasks stall — not just the symptom."},{"id":"t3_q21","tier":3,"tier_name":"Work & Productivity","question":"When you're doing your best work, what's the single most important ingredient?","type":"open_text","placeholder":"Describe what 'perfect working conditions' looks like for you (2-3 sentences max)","skippable":true,"meta_profiling":"Open text response style here is itself a signal. Very short = low verbosity. Detailed + organized = structured thinker. Stream-of-consciousness = verbal processor.","dimension":"work.ideal_conditions","why_this_matters":"Your words, not a dropdown. This goes directly into your AI profile as-is."}]`),n={tier:x,tier_name:A,tier_intro:j,tier_complete:C,questions:P},N=4,S="Personality & Values",T="The deepest layer. Not a clinical assessment — a practical personality map that tells AI how to actually treat you as a human. What motivates you, how you handle stress, how you relate to risk and change. Real questions that get at real answers. 6-8 minutes.",D={headline:"Full personality profile built.",body:"This is the layer most tools skip entirely. AI now has a complete picture of you — not just preferences, but how you think, work, and navigate the world. Your profile is ready to export. One profile, any AI platform."},W=JSON.parse(`[{"id":"t4_q01","tier":4,"tier_name":"Personality & Values","question":"Friday night, zero plans, zero obligations. Your ideal scenario?","type":"scenario","options":[{"value":"people","label":"Call someone, go out, be around people — recharge through connection","maps_to":{"dimension":"personality.extraversion","value":"high"},"big_five":"E+"},{"value":"small_group","label":"One or two close people — meaningful conversation over noise","maps_to":{"dimension":"personality.extraversion","value":"moderate"},"big_five":"E~"},{"value":"solo_recharge","label":"Alone time — solo project, show, book. Complete recharge.","maps_to":{"dimension":"personality.extraversion","value":"low"},"big_five":"E-"},{"value":"depends_week","label":"Depends entirely on how the week went","maps_to":{"dimension":"personality.extraversion","value":"adaptive"}}],"skippable":false,"meta_profiling":"Classic extraversion scenario — response time and length give secondary signals. Also note: if they said 'depends on week' — this is a self-aware introvert or ambivert.","dimension":"personality.extraversion","why_this_matters":"Social energy preferences affect how AI engages — does it create space or fill it?"},{"id":"t4_q02","tier":4,"tier_name":"Personality & Values","question":"After a full day of socializing — meeting people, presentations, group work — you feel...","type":"scenario","options":[{"value":"energized","label":"Energized — people fuel me","maps_to":{"dimension":"personality.social_battery","value":"extrovert"}},{"value":"satisfied_tired","label":"Satisfied but ready for quiet — good day, now I need to recharge alone","maps_to":{"dimension":"personality.social_battery","value":"ambivert"}},{"value":"drained","label":"Drained — even if it went well, I need solo time to recover","maps_to":{"dimension":"personality.social_battery","value":"introvert"}},{"value":"depends_people","label":"Depends entirely on who I was with","maps_to":{"dimension":"personality.social_battery","value":"selective"}}],"skippable":true,"meta_profiling":"Social battery combined with extraversion from t4_q01 gives full introvert/extrovert picture. Inconsistency between the two = situational extraversion (ambivert or context-sensitive).","dimension":"personality.social_battery","why_this_matters":"AI calibrates how much social framing and collaboration it suggests — and when to leave you alone."},{"id":"t4_q03","tier":4,"tier_name":"Personality & Values","question":"What actually motivates you to push through hard work? Your honest answer:","type":"select","options":[{"value":"building_something","label":"Building something that didn't exist before — creation itself","maps_to":{"dimension":"personality.core_motivation","value":"creation"}},{"value":"freedom","label":"Freedom — financial, time, or location freedom as the outcome","maps_to":{"dimension":"personality.core_motivation","value":"autonomy"}},{"value":"recognition","label":"Recognition — being seen and respected for what you've done","maps_to":{"dimension":"personality.core_motivation","value":"recognition"}},{"value":"impact","label":"Impact — knowing it matters to real people","maps_to":{"dimension":"personality.core_motivation","value":"impact"}},{"value":"mastery","label":"Mastery — getting really, genuinely good at something","maps_to":{"dimension":"personality.core_motivation","value":"mastery"}},{"value":"competition","label":"Winning — being better than the alternative or the competition","maps_to":{"dimension":"personality.core_motivation","value":"competition"}}],"skippable":false,"meta_profiling":"Core motivation is a high-signal dimension that should inform ALL AI framing. Recognition-motivated people respond to different language than autonomy-motivated ones.","dimension":"personality.core_motivation","why_this_matters":"AI frames recommendations, challenges, and progress in terms of what actually moves you."},{"id":"t4_q04","tier":4,"tier_name":"Personality & Values","question":"If you could keep only 3 things in your life — which 3? (rank or pick)","type":"ranking","instruction":"Pick your top 3 — order them if you can","options":[{"value":"close_relationships","label":"Close relationships — family, real friends","maps_to":{"dimension":"personality.values_hierarchy","value":"relationships"}},{"value":"freedom_autonomy","label":"Freedom — ability to do what you want, when you want","maps_to":{"dimension":"personality.values_hierarchy","value":"autonomy"}},{"value":"meaningful_work","label":"Meaningful work — building something that matters","maps_to":{"dimension":"personality.values_hierarchy","value":"purpose"}},{"value":"health","label":"Health — physical and mental wellbeing","maps_to":{"dimension":"personality.values_hierarchy","value":"health"}},{"value":"financial_security","label":"Financial security — not worrying about money","maps_to":{"dimension":"personality.values_hierarchy","value":"security"}},{"value":"growth","label":"Growth — constantly learning and improving","maps_to":{"dimension":"personality.values_hierarchy","value":"growth"}}],"max_selections":3,"skippable":true,"meta_profiling":"Values hierarchy is the deepest profiling dimension. Inconsistencies with stated motivations (t4_q03) are often the most interesting signals — what people say vs what they choose.","dimension":"personality.values_hierarchy","why_this_matters":"AI understands what's actually at stake for you — not just what you're working on."},{"id":"t4_q05","tier":4,"tier_name":"Personality & Values","question":"An opportunity lands in front of you — potentially big, but genuinely uncertain. You:","type":"scenario","options":[{"value":"jump_in","label":"Jump in — uncertainty is part of the opportunity","maps_to":{"dimension":"personality.risk_tolerance","value":"high"}},{"value":"calculate_first","label":"Calculate the downside first — if I can survive the worst case, I'm in","maps_to":{"dimension":"personality.risk_tolerance","value":"calculated"}},{"value":"need_more_info","label":"Get more information before deciding — insufficient data","maps_to":{"dimension":"personality.risk_tolerance","value":"information_seeking"}},{"value":"pass","label":"Probably pass unless someone I trust validates it strongly","maps_to":{"dimension":"personality.risk_tolerance","value":"low"}}],"skippable":true,"meta_profiling":"Risk tolerance cross-references with decision style from Tier 2. Consistent picture = note as stable trait. Contradictions = note for context-dependency.","dimension":"personality.risk_tolerance","why_this_matters":"AI knows whether to present options with upside-first or risk-first framing."},{"id":"t4_q06","tier":4,"tier_name":"Personality & Values","question":"You and someone you work with have a genuine disagreement. You tend to:","type":"scenario","options":[{"value":"direct_address","label":"Address it directly and immediately — let's settle this","maps_to":{"dimension":"personality.conflict_style","value":"direct"}},{"value":"avoid","label":"Avoid it if possible — not worth the energy unless it really matters","maps_to":{"dimension":"personality.conflict_style","value":"avoidant"}},{"value":"process_first","label":"Process internally first, then address when I have a clear head","maps_to":{"dimension":"personality.conflict_style","value":"reflective_then_direct"}},{"value":"find_middle","label":"Look for the middle ground proactively — meet them halfway","maps_to":{"dimension":"personality.conflict_style","value":"mediating"}}],"skippable":true,"meta_profiling":"Conflict style affects how AI handles disagreements with user. Avoidant = AI should soften challenges. Direct = AI can disagree more directly.","dimension":"personality.conflict_style","why_this_matters":"Sets the tone for how AI disagrees with you — and how persistent it should be when you push back."},{"id":"t4_q07","tier":4,"tier_name":"Personality & Values","question":"Under genuine stress — not mild inconvenience, but real pressure — what do people around you notice?","type":"scenario","options":[{"value":"quiet_withdrawal","label":"I go quiet — process internally, want to be left alone","maps_to":{"dimension":"personality.stress_response","value":"withdraw"}},{"value":"irritable","label":"Short-tempered — I snap, then apologize after","maps_to":{"dimension":"personality.stress_response","value":"irritable"}},{"value":"hyperfocus_on_problem","label":"Lock in on the problem — tunnel vision until it's solved","maps_to":{"dimension":"personality.stress_response","value":"problem_lock"}},{"value":"talk_it_out","label":"Talk excessively — I need to verbally process to calm down","maps_to":{"dimension":"personality.stress_response","value":"verbal_vent"}},{"value":"freeze","label":"Freeze up — hard to make decisions or take action","maps_to":{"dimension":"personality.stress_response","value":"freeze"}}],"skippable":true,"meta_profiling":"Stress response is a critical safety dimension — affects how AI should behave when user signals high pressure. Irritable pattern = AI should reduce friction, not ask questions. Freeze = AI should simplify and give one clear action.","dimension":"personality.stress_response","why_this_matters":"When you're under pressure, AI adapts its approach to match how you actually handle stress."},{"id":"t4_q08","tier":4,"tier_name":"Personality & Values","question":"Deadline tomorrow, the thing you need isn't ready, and it's your call. First thought?","type":"scenario","options":[{"value":"problem_solve","label":"What can I actually do right now? I'm already making a list.","maps_to":{"dimension":"personality.stress_coping_style","value":"action_oriented"}},{"value":"communicate_proactively","label":"Communicate proactively — tell the stakeholder now, not at deadline","maps_to":{"dimension":"personality.stress_coping_style","value":"transparent"}},{"value":"push_harder","label":"Push harder — I'll pull an all-nighter if I have to","maps_to":{"dimension":"personality.stress_coping_style","value":"effort_escalation"}},{"value":"spiral_first","label":"Brief spiral of 'this is bad', then I find my feet and act","maps_to":{"dimension":"personality.stress_coping_style","value":"panic_then_act"}}],"skippable":true,"meta_profiling":"Stress coping style is the activation pattern under pressure. Spiral-then-act = AI should give one clear action to break the spiral. Transparent = AI should help draft communications early.","dimension":"personality.stress_coping_style","why_this_matters":"AI provides the right kind of support during crunch — action lists, communications, or just helping you break the spiral."},{"id":"t4_q09","tier":4,"tier_name":"Personality & Values","question":"Your company reorganizes everything — new team, new tools, new processes. You feel:","type":"scenario","options":[{"value":"energized","label":"Energized — change is interesting, fresh start","maps_to":{"dimension":"personality.change_adaptability","value":"high"}},{"value":"cautiously_open","label":"Cautiously open — depends on what's changing and why","maps_to":{"dimension":"personality.change_adaptability","value":"conditional"}},{"value":"unsettled_adapts","label":"Unsettled initially but I adapt — I just need to find the new pattern","maps_to":{"dimension":"personality.change_adaptability","value":"slow_but_ok"}},{"value":"resistant","label":"Resistant — I prefer the known even if it's imperfect","maps_to":{"dimension":"personality.change_adaptability","value":"low"}}],"skippable":true,"meta_profiling":null,"dimension":"personality.change_adaptability","why_this_matters":"AI handles tool changes, workflow suggestions, and pivots — does it push the new thing hard or help you transition gently?"},{"id":"t4_q10","tier":4,"tier_name":"Personality & Values","question":"Your boss gives you an instruction you genuinely disagree with. You:","type":"scenario","options":[{"value":"voice_then_do","label":"Voice my disagreement once, clearly — then do it if they hold the call","maps_to":{"dimension":"personality.authority_orientation","value":"assertive_compliant"}},{"value":"push_back_hard","label":"Push back hard — I can't execute something I think is wrong without a fight","maps_to":{"dimension":"personality.authority_orientation","value":"challenging"}},{"value":"just_do_it","label":"Do it — they have context I might not, and hierarchy exists for a reason","maps_to":{"dimension":"personality.authority_orientation","value":"deferential"}},{"value":"find_workaround","label":"Nod and find a way to do it that I think is better","maps_to":{"dimension":"personality.authority_orientation","value":"autonomous"}}],"skippable":true,"meta_profiling":"Authority orientation reveals relationship with hierarchical structures. High autonomy + challenging = AI should not be authoritative; should present options. Deferential = AI can be more directive.","dimension":"personality.authority_orientation","why_this_matters":"Shapes whether AI acts as an equal collaborator or a helpful assistant."},{"id":"t4_q11","tier":4,"tier_name":"Personality & Values","question":"Trolley problem, slightly less deadly: You can do something that helps 10 people but hurts 1 person who doesn't deserve it. You...","type":"scenario","options":[{"value":"do_it_utilitarian","label":"Do it — the math is clear, 10 > 1","maps_to":{"dimension":"personality.ethical_framework","value":"consequentialist"}},{"value":"refuse_deontological","label":"Don't do it — some things are wrong regardless of outcome","maps_to":{"dimension":"personality.ethical_framework","value":"rule_based"}},{"value":"depends_context","label":"Depends on who the 1 is and how much they're hurt","maps_to":{"dimension":"personality.ethical_framework","value":"contextual"}},{"value":"find_third_option","label":"Find a way to help the 10 without hurting the 1 — accept neither option","maps_to":{"dimension":"personality.ethical_framework","value":"problem_solver"}}],"skippable":true,"meta_profiling":"Ethical framework is not about judging — it's about how AI should frame trade-off decisions. Consequentialist = present outcomes. Rule-based = present principles. Problem-solver = AI should always look for third options.","dimension":"personality.ethical_framework","why_this_matters":"How AI presents decisions with trade-offs — and whether it looks for alternatives or just gives you the choice."},{"id":"t4_q12","tier":4,"tier_name":"Personality & Values","question":"You're on hold for 20 minutes. The task will take 2 minutes when someone answers. You:","type":"scenario","options":[{"value":"stay_focused","label":"Stay on the line, focused — I need this resolved","maps_to":{"dimension":"personality.patience_level","value":"high"}},{"value":"multitask_hold","label":"Put on hold music and do something else","maps_to":{"dimension":"personality.patience_level","value":"moderate"}},{"value":"escalate","label":"Hang up after 5 minutes and find a faster way","maps_to":{"dimension":"personality.patience_level","value":"low"}},{"value":"irrationally_irritated","label":"Irrationally irritated by the entire situation out of proportion to what it is","maps_to":{"dimension":"personality.patience_level","value":"very_low"}}],"skippable":true,"meta_profiling":"Patience level cross-references with verbosity preference and feedback style. Very low patience + minimal verbosity = user who will not re-engage AI that wastes their time even once.","dimension":"personality.patience_level","why_this_matters":"AI calibrates its own response time, interruptions, and willingness to take roundabout paths."},{"id":"t4_q13","tier":4,"tier_name":"Personality & Values","question":"Plans fall through at the last minute — something you were looking forward to. Your first thought?","type":"scenario","options":[{"value":"find_alternative","label":"OK, what else can I do with this time? Immediately looking for alternatives.","maps_to":{"dimension":"personality.optimism","value":"high"}},{"value":"disappointed_regroup","label":"Disappointed, but I regroup quickly — it's fine","maps_to":{"dimension":"personality.optimism","value":"moderate"}},{"value":"frustrated_then_ok","label":"Genuinely frustrated — I sit with that for a bit, then move on","maps_to":{"dimension":"personality.optimism","value":"realistic"}},{"value":"expected_it","label":"Honestly expected it — things usually do fall through","maps_to":{"dimension":"personality.optimism","value":"low"},"triggers":["t4_q13a"]}],"skippable":true,"meta_profiling":"Optimism baseline shapes how AI frames uncertainty and setbacks. Low optimism = AI should not overpromise or be relentlessly positive.","dimension":"personality.optimism","why_this_matters":"AI matches its emotional tone to your baseline — doesn't try to artificially cheer up a realistic person."},{"id":"t4_q13a","tier":4,"tier_name":"Personality & Values","question":"Where does that expectation come from?","type":"select","is_followup":true,"parent_question":"t4_q13","options":[{"value":"self_protection","label":"I'd rather be pleasantly surprised than disappointed — it's self-protection","maps_to":{"dimension":"personality.pessimism_type","value":"protective"}},{"value":"life_experience","label":"Experience — things genuinely do fall through more often than not for me","maps_to":{"dimension":"personality.pessimism_type","value":"experiential"}},{"value":"just_realistic","label":"I'm just calibrated — not cynical, just realistic about probabilities","maps_to":{"dimension":"personality.pessimism_type","value":"calibrated"}}],"skippable":true,"meta_profiling":"The framing they choose reveals self-narrative around pessimism — protective vs experiential vs calibrated each require different AI handling.","dimension":"personality.pessimism_type","why_this_matters":"Helps AI calibrate whether to offer encouragement, validation, or just match your realistic tone."},{"id":"t4_q14","tier":4,"tier_name":"Personality & Values","question":"New colleague starts Monday. Before you've met them, your default assumption about them?","type":"scenario","options":[{"value":"they_are_good","label":"They're probably competent and well-intentioned — trust until disproven","maps_to":{"dimension":"personality.trust_default","value":"high"}},{"value":"neutral_observe","label":"Neutral — I'll form a view once I see them work","maps_to":{"dimension":"personality.trust_default","value":"moderate"}},{"value":"cautious_earn_it","label":"Cautious — trust is earned, not assumed","maps_to":{"dimension":"personality.trust_default","value":"low"}},{"value":"depends_context","label":"Depends on how they were hired and who they are","maps_to":{"dimension":"personality.trust_default","value":"conditional"}}],"skippable":true,"meta_profiling":"Trust default affects how AI should frame its own relationship with the user. High trust = AI can be direct and proactive. Low trust = AI should show its reasoning, not just its conclusions.","dimension":"personality.trust_default","why_this_matters":"AI knows whether to lead with conclusions or always show its work so you can verify."},{"id":"t4_q15","tier":4,"tier_name":"Personality & Values","question":"You just shipped something. It works, people are happy, but you KNOW there's a subtle issue nobody else will notice. You...","type":"scenario","options":[{"value":"perfectionist","label":"Fix it immediately — I can't leave it. It'll eat at me until I do.","maps_to":{"dimension":"personality.perfectionism","value":"high"},"triggers":["t4_q15a"]},{"value":"pride_in_quality","label":"Note it for later — I care, but I can live with it for now","maps_to":{"dimension":"personality.perfectionism","value":"moderate"}},{"value":"good_enough","label":"Move on — it works, nobody notices, there's more important stuff to do","maps_to":{"dimension":"personality.perfectionism","value":"pragmatic"}},{"value":"context_dependent","label":"Depends what it is — a typo I can live with, a logic flaw I can't","maps_to":{"dimension":"personality.perfectionism","value":"selective"}}],"skippable":true,"meta_profiling":"High perfectionism + incomplete completion (t3_q16 perfectionist) = reinforced pattern. The scenario reveals actual behavior vs stated preference — someone who says 'I'm pragmatic' but admits they'd fix it = hidden perfectionist.","dimension":"personality.perfectionism","why_this_matters":"AI knows whether to push you to ship sooner or help you find the right 'done' threshold."},{"id":"t4_q15a","tier":4,"tier_name":"Personality & Values","question":"Is your perfectionism usually productive (drives quality) or does it sometimes hold you back?","type":"select","is_followup":true,"parent_question":"t4_q15","options":[{"value":"mostly_productive","label":"Mostly productive — it's a strength I use consciously","maps_to":{"dimension":"personality.perfectionism_impact","value":"productive"}},{"value":"mixed","label":"Mixed — productive on things I care about, paralyzing on others","maps_to":{"dimension":"personality.perfectionism_impact","value":"mixed"}},{"value":"often_blocks","label":"Often blocks me — I know it's a problem","maps_to":{"dimension":"personality.perfectionism_impact","value":"blocking"}}],"skippable":true,"meta_profiling":null,"dimension":"personality.perfectionism_impact","why_this_matters":null},{"id":"t4_q16","tier":4,"tier_name":"Personality & Values","question":"Something unexpected and wonderful happens — you got the deal, your project got featured, genuine praise from someone you respect. Your first instinct?","type":"scenario","options":[{"value":"share_immediately","label":"Share it immediately — call someone, post it, tell the world","maps_to":{"dimension":"personality.positive_affect_expression","value":"extrovert_sharing"}},{"value":"internal_joy","label":"Feel it internally — deep satisfaction. Maybe tell one person later.","maps_to":{"dimension":"personality.positive_affect_expression","value":"internal_processor"}},{"value":"skeptical","label":"Mild suspicion — when does the other shoe drop?","maps_to":{"dimension":"personality.positive_affect_expression","value":"cautious_optimist"}},{"value":"move_to_next","label":"Acknowledge it, then immediately move to what's next","maps_to":{"dimension":"personality.positive_affect_expression","value":"forward_focus"}}],"skippable":true,"meta_profiling":"Cautious optimist response combined with high conscientiousness from other signals = anxiety-adjacent trait. Note for gentle challenge handling.","dimension":"personality.positive_affect_expression","why_this_matters":"AI calibrates celebration and acknowledgment to how you actually receive good news."},{"id":"t4_q17","tier":4,"tier_name":"Personality & Values","question":"A friend describes you in 3 words to someone who's never met you. They'd most likely say...","type":"multi_select","instruction":"Pick the 3 that ring most true","options":[{"value":"direct","label":"Direct","maps_to":{"dimension":"personality.self_perception","value":"direct"}},{"value":"creative","label":"Creative","maps_to":{"dimension":"personality.self_perception","value":"creative"}},{"value":"analytical","label":"Analytical","maps_to":{"dimension":"personality.self_perception","value":"analytical"}},{"value":"reliable","label":"Reliable","maps_to":{"dimension":"personality.self_perception","value":"reliable"}},{"value":"intense","label":"Intense","maps_to":{"dimension":"personality.self_perception","value":"intense"}},{"value":"curious","label":"Curious","maps_to":{"dimension":"personality.self_perception","value":"curious"}},{"value":"independent","label":"Independent","maps_to":{"dimension":"personality.self_perception","value":"independent"}},{"value":"empathetic","label":"Empathetic","maps_to":{"dimension":"personality.self_perception","value":"empathetic"}},{"value":"ambitious","label":"Ambitious","maps_to":{"dimension":"personality.self_perception","value":"ambitious"}},{"value":"chaotic","label":"Chaotic (in a good way)","maps_to":{"dimension":"personality.self_perception","value":"chaotic"}}],"max_selections":3,"skippable":true,"meta_profiling":"Self-perception is a meta-signal. Cross-reference with how they actually behaved throughout the profiling — answers that contradict self-perception are the most interesting. Note incongruence without flagging it.","dimension":"personality.self_perception","why_this_matters":"AI adjusts its relational style to match how you see yourself — not project a different identity onto you."},{"id":"t4_q18","tier":4,"tier_name":"Personality & Values","question":"You've finished a piece of work you're genuinely proud of. Nobody's seen it yet. You...","type":"scenario","options":[{"value":"internal_compass","label":"Already know it's good — I don't need anyone to tell me","maps_to":{"dimension":"personality.validation_need","value":"low"}},{"value":"like_it_but_not_dependent","label":"Feel good about it, but it'd be nice if someone confirmed","maps_to":{"dimension":"personality.validation_need","value":"moderate"}},{"value":"need_one_trusted","label":"Need to show one person I trust before I feel confident sharing widely","maps_to":{"dimension":"personality.validation_need","value":"trusted_source"}},{"value":"high_need","label":"Won't feel sure about it until someone else reacts — my own judgment isn't enough","maps_to":{"dimension":"personality.validation_need","value":"high"}}],"skippable":true,"meta_profiling":"High validation need = AI should proactively affirm direction and signal agreement. Low = AI should not be sycophantic, just direct. Note: response time here is a secondary signal — fast pick = confident in self-knowledge.","dimension":"personality.validation_need","why_this_matters":"AI calibrates how much it confirms, affirms, and checks in — vs just executes without commentary."},{"id":"t4_q19","tier":4,"tier_name":"Personality & Values","question":"You're deciding between two things — one you know is right, one that sounds exciting right now. You tend to:","type":"scenario","options":[{"value":"long_term_wins","label":"Long-term wins — I can delay gratification pretty well","maps_to":{"dimension":"personality.impulse_control","value":"high"}},{"value":"50_50","label":"About 50/50 — depends on how exciting the short-term option is","maps_to":{"dimension":"personality.impulse_control","value":"moderate"}},{"value":"short_term_pulls","label":"Short-term often wins — I'm working on this","maps_to":{"dimension":"personality.impulse_control","value":"low"},"triggers":["t4_q19a"]},{"value":"rationalize","label":"I rationalize the short-term choice as actually being better long-term","maps_to":{"dimension":"personality.impulse_control","value":"rationalized_impulsivity"}}],"skippable":true,"meta_profiling":"Impulsivity indicator cross-references with spending patterns implied in Tier 7 (life context). Low impulse control = AI should add 'sleep on it' friction to big decisions.","dimension":"personality.impulse_control","why_this_matters":"AI knows whether to present options with equal weight or add a pause before big decisions."},{"id":"t4_q19a","tier":4,"tier_name":"Personality & Values","question":"In which areas does this show up most?","type":"multi_select","is_followup":true,"parent_question":"t4_q19","instruction":"Pick all that apply","options":[{"value":"purchases","label":"Purchases — I buy things I didn't plan on","maps_to":{"dimension":"personality.impulsivity_domains","value":"spending"}},{"value":"projects","label":"New projects — I start things before finishing what's open","maps_to":{"dimension":"personality.impulsivity_domains","value":"project_hopping"}},{"value":"decisions","label":"Decisions — I commit too fast","maps_to":{"dimension":"personality.impulsivity_domains","value":"decisions"}},{"value":"eating","label":"Food and health habits","maps_to":{"dimension":"personality.impulsivity_domains","value":"health_habits"}}],"max_selections":4,"skippable":true,"meta_profiling":"project_hopping = strong ADHD-associated pattern. Cross-reference with completion_pattern from Tier 3.","dimension":"personality.impulsivity_domains","why_this_matters":null},{"id":"t4_q21","tier":4,"tier_name":"Personality & Values","question":"Last one. If AI could do one thing differently that almost every AI gets wrong for you — what would it be?","type":"open_text","placeholder":"Your honest answer here — this goes directly into your profile","skippable":true,"meta_profiling":"This is the highest-value open text question in the entire bank. Response length, content, and tone carry enormous signal. Note: very short answer = either they're satisfied or they're low-verbosity. Very detailed = high investment, pain points are real. Save verbatim.","dimension":"personality.ai_pet_peeve","why_this_matters":"Your words, verbatim. The one thing your AI profile is built around fixing for you."}]`),s={tier:N,tier_name:S,tier_intro:T,tier_complete:D,questions:W},Y=5,H="Neurodivergent Profile",E="This section is completely optional. It helps AI adapt to how YOUR brain actually works — not how textbooks say brains should work. No diagnosis needed. No judgment. We're asking about experiences and adaptations, not labels. Skip anything that doesn't feel relevant.",L={headline:"Brain OS profile saved.",body:"Most AI tools assume everyone's brain works the same way. Yours now doesn't. AI will adapt pacing, structure, reminders, and task framing to how you actually function — not the neurotypical default. This is one of the highest-impact sections in the whole profile."},z=JSON.parse(`[{"id":"t5_q01","tier":5,"tier_name":"Neurodivergent Profile","question":"When you sit down to start something important, your brain...","type":"select","options":[{"value":"just_starts","label":"Just starts — I sit down, I begin, no drama","maps_to":{"dimension":"neurodivergent.task_initiation","value":"easy"}},{"value":"needs_ritual","label":"Needs a warm-up — coffee, music, clearing desk, a small easy task first","maps_to":{"dimension":"neurodivergent.task_initiation","value":"ritual_dependent"}},{"value":"procrastinates_then_rush","label":"Procrastinates until pressure kicks in, then hyperfocuses at the last minute","maps_to":{"dimension":"neurodivergent.task_initiation","value":"deadline_activated"},"triggers":["t5_q01a"]},{"value":"paralyzed","label":"Often freezes — knows what to do but can't make the first move","maps_to":{"dimension":"neurodivergent.task_initiation","value":"initiation_blocked"},"triggers":["t5_q01a"]},{"value":"depends_interest","label":"Completely depends — easy if it's interesting, nearly impossible if it's not","maps_to":{"dimension":"neurodivergent.task_initiation","value":"interest_gated"}}],"skippable":true,"meta_profiling":"Response speed and length here are secondary signals. Paralysis/deadline patterns are strong ADHD indicators. 'Depends on interest' = interest-based nervous system.","dimension":"neurodivergent.task_initiation","why_this_matters":"AI can adjust how it frames task starts — breaking them into smaller entry points or adding urgency framing based on what actually gets you moving."},{"id":"t5_q01a","tier":5,"tier_name":"Neurodivergent Profile","question":"What actually helps you start when you're stuck?","type":"multi_select","is_followup":true,"parent_question":"t5_q01","options":[{"value":"body_double","label":"Someone else in the room (or on video) working alongside me","maps_to":{"dimension":"neurodivergent.adhd_adaptations","value":"body_doubling"}},{"value":"timer","label":"Setting a timer — even 5 minutes","maps_to":{"dimension":"neurodivergent.adhd_adaptations","value":"timers"}},{"value":"declare_intention","label":"Telling someone what I'm about to do","maps_to":{"dimension":"neurodivergent.adhd_adaptations","value":"accountability"}},{"value":"smallest_step","label":"Breaking it to the smallest possible first action","maps_to":{"dimension":"neurodivergent.adhd_adaptations","value":"micro_steps"}},{"value":"environment_change","label":"Changing location (cafe, different room)","maps_to":{"dimension":"neurodivergent.adhd_adaptations","value":"environment_change"}},{"value":"music_noise","label":"Specific music or background noise","maps_to":{"dimension":"neurodivergent.adhd_adaptations","value":"auditory_anchor"}},{"value":"nothing_works","label":"Honestly, nothing reliable — it's random","maps_to":{"dimension":"neurodivergent.task_initiation","value":"unpredictable"}}],"skippable":true,"meta_profiling":"Which adaptations they've already discovered tells you about their self-awareness and coping sophistication.","dimension":"neurodivergent.adhd_adaptations","why_this_matters":"AI can actively suggest or simulate these conditions when helping you start tasks."},{"id":"t5_q02","tier":5,"tier_name":"Neurodivergent Profile","question":"You think 'I'll just do this quick thing — 10 minutes max.' You look up and it's been...","type":"select","options":[{"value":"accurate","label":"About what I expected — my time estimates are usually close","maps_to":{"dimension":"neurodivergent.time_perception","value":"accurate"}},{"value":"slightly_off","label":"A bit longer, but not drastically — maybe 1.5x what I thought","maps_to":{"dimension":"neurodivergent.time_perception","value":"slightly_impaired"}},{"value":"way_longer","label":"45 minutes to 2 hours — time genuinely disappears","maps_to":{"dimension":"neurodivergent.time_perception","value":"impaired"},"triggers":["t5_q02a"]},{"value":"no_idea","label":"I genuinely have no idea until I check my phone — could be 10 min or 3 hours","maps_to":{"dimension":"neurodivergent.time_perception","value":"severely_impaired"},"triggers":["t5_q02a"]}],"skippable":true,"meta_profiling":"Time blindness is one of the most impactful ADHD traits for AI assistance. Note their certainty — people with time blindness often phrase this with humor or resignation.","dimension":"neurodivergent.time_perception","why_this_matters":"Time blindness changes how AI should structure task estimates, reminders, and planning — it's not about discipline, it's about perception."},{"id":"t5_q02a","tier":5,"tier_name":"Neurodivergent Profile","question":"Which tools or strategies actually help you with time?","type":"multi_select","is_followup":true,"parent_question":"t5_q02","options":[{"value":"visual_timer","label":"Visual timers (Time Timer, phone timer visible on screen)"},{"value":"alarms","label":"Multiple calendar alarms — including 'start getting ready' alerts"},{"value":"time_anchors","label":"Anchoring to fixed events ('after lunch', 'before 3pm call')"},{"value":"pomodoro","label":"Pomodoro or fixed work/break intervals"},{"value":"external_deadlines","label":"External deadlines from other people — self-imposed ones don't work"},{"value":"nothing","label":"Nothing reliable — I'm just always late or surprised"}],"skippable":true,"meta_profiling":"Check if they mention external deadlines specifically — strong signal that self-regulation is insufficient alone.","dimension":"neurodivergent.time_tools","why_this_matters":"AI can proactively use the strategies that actually work for you."},{"id":"t5_q03","tier":5,"tier_name":"Neurodivergent Profile","question":"When something REALLY grabs your attention — a project, a topic, a problem...","type":"select","options":[{"value":"no_hyperfocus","label":"I don't really experience this — I stay pretty consistent regardless of interest","maps_to":{"dimension":"neurodivergent.hyperfocus","value":"absent"}},{"value":"mild_flow","label":"I get into flow states, but I can exit when needed","maps_to":{"dimension":"neurodivergent.hyperfocus","value":"mild_flow"}},{"value":"hyperfocus_exits","label":"I go deep and lose track of time, but external interruptions can pull me out","maps_to":{"dimension":"neurodivergent.hyperfocus","value":"moderate"}},{"value":"hyperfocus_locked","label":"I fully disappear — hours pass, I forget to eat, interruptions feel physically jarring","maps_to":{"dimension":"neurodivergent.hyperfocus","value":"intense"},"triggers":["t5_q03a"]}],"skippable":true,"meta_profiling":"Intensity of description is itself a signal — people with strong hyperfocus often describe it vividly or with a mix of pride and frustration.","dimension":"neurodivergent.hyperfocus","why_this_matters":"Hyperfocus is a superpower and a liability. AI can help harness it strategically and protect against its costs."},{"id":"t5_q03a","tier":5,"tier_name":"Neurodivergent Profile","question":"After a hyperfocus session, you typically feel...","type":"select","is_followup":true,"parent_question":"t5_q03","options":[{"value":"energized","label":"Energized — that was productive and satisfying"},{"value":"crash_mild","label":"Slightly drained — need a break but recovered quickly"},{"value":"crash_severe","label":"Wiped out — rest of day is often gone"},{"value":"disoriented","label":"Disoriented — takes a while to re-enter normal life"}],"skippable":true,"meta_profiling":"Post-hyperfocus crash pattern informs how AI should structure recovery time in planning.","dimension":"neurodivergent.hyperfocus_recovery","why_this_matters":"Knowing the recovery cost helps AI plan what to schedule after deep work sessions."},{"id":"t5_q04","tier":5,"tier_name":"Neurodivergent Profile","question":"You're doing a boring but necessary task. Your brain starts wanting to...","type":"multi_select","options":[{"value":"check_phone","label":"Check phone — notifications, social, anything","maps_to":{"dimension":"neurodivergent.dopamine_seeking","value":"digital_stimulation"}},{"value":"new_tab","label":"Open a new tab 'just quickly'","maps_to":{"dimension":"neurodivergent.dopamine_seeking","value":"task_switching"}},{"value":"snack","label":"Get a snack or drink — suddenly very hungry","maps_to":{"dimension":"neurodivergent.dopamine_seeking","value":"oral_stimulation"}},{"value":"reorganize","label":"Reorganize or clean something nearby","maps_to":{"dimension":"neurodivergent.dopamine_seeking","value":"productive_procrastination"}},{"value":"daydream","label":"Just... drift off into thinking about something else entirely","maps_to":{"dimension":"neurodivergent.dopamine_seeking","value":"internal_escape"}},{"value":"music_podcast","label":"Put on music or a podcast to make it bearable","maps_to":{"dimension":"neurodivergent.dopamine_seeking","value":"auditory_stimulation"}},{"value":"push_through","label":"Push through — I have decent tolerance for boring work","maps_to":{"dimension":"neurodivergent.dopamine_seeking","value":"low"}}],"skippable":true,"meta_profiling":"Multiple selections = higher dopamine-seeking tendency. Phone + new tab + snack = strong ADHD pattern. Note if they selected 'push through' alongside others — might be masking.","dimension":"neurodivergent.dopamine_seeking","why_this_matters":"AI can gamify, chunk, or pair boring tasks with stimulation based on your specific patterns."},{"id":"t5_q05","tier":5,"tier_name":"Neurodivergent Profile","question":"Your ideal work environment sound level is...","type":"spectrum","spectrum":{"min":1,"max":5,"min_label":"Complete silence — any noise breaks concentration","max_label":"Loud and busy — I focus better in a cafe or with music","mid_label":"Low background noise or ambient sounds"},"skippable":true,"meta_profiling":"Extremes on either end can indicate sensory processing differences. Note this against their task initiation style.","dimension":"neurodivergent.sensory_audio","why_this_matters":"Affects environment recommendations, focus music suggestions, and whether to recommend background noise tools."},{"id":"t5_q06","tier":5,"tier_name":"Neurodivergent Profile","question":"Someone gives you a 4-step verbal instruction. You...","type":"select","options":[{"value":"remember_all","label":"Remember all 4 steps easily and execute them","maps_to":{"dimension":"neurodivergent.working_memory","value":"strong"}},{"value":"remember_first_last","label":"Remember the first and last steps, fuzzy on the middle","maps_to":{"dimension":"neurodivergent.working_memory","value":"moderate"}},{"value":"write_it_down","label":"Immediately write it down — I know I'll lose it otherwise","maps_to":{"dimension":"neurodivergent.working_memory","value":"compensated"}},{"value":"remember_two","label":"Retain about 2 steps before it starts dropping off","maps_to":{"dimension":"neurodivergent.working_memory","value":"limited"}},{"value":"ask_repeat","label":"Ask them to slow down or repeat — verbal instructions don't stick","maps_to":{"dimension":"neurodivergent.working_memory","value":"impaired"}}],"skippable":true,"meta_profiling":"Working memory is one of the most consistently impacted areas in ADHD. The 'compensated' response shows strong self-awareness.","dimension":"neurodivergent.working_memory","why_this_matters":"AI adjusts how it delivers multi-step instructions — chunking, numbered lists, or asking you to confirm each step."},{"id":"t5_q07","tier":5,"tier_name":"Neurodivergent Profile","question":"You're mid-task when someone interrupts you. Getting back to where you were feels like...","type":"select","options":[{"value":"easy_resumption","label":"Easy — I pick right back up","maps_to":{"dimension":"neurodivergent.task_switching","value":"flexible"}},{"value":"takes_moment","label":"Takes a moment to reload — maybe 2-5 minutes to get back","maps_to":{"dimension":"neurodivergent.task_switching","value":"moderate"}},{"value":"lost_thread","label":"The thread is partially lost — I usually have to re-read what I was doing","maps_to":{"dimension":"neurodivergent.task_switching","value":"impaired"}},{"value":"task_dead","label":"The task is basically dead — I rarely return to it after interruption","maps_to":{"dimension":"neurodivergent.task_switching","value":"severely_impaired"},"triggers":["t5_q07a"]}],"skippable":true,"meta_profiling":"Interruption sensitivity is separate from introversion. Someone who gets frustrated at interruptions may be protecting fragile focus, not being antisocial.","dimension":"neurodivergent.task_switching","why_this_matters":"AI can build in 'do not interrupt' framing and help you use context notes to resume interrupted tasks."},{"id":"t5_q07a","tier":5,"tier_name":"Neurodivergent Profile","question":"What helps you protect focus from interruptions?","type":"multi_select","is_followup":true,"parent_question":"t5_q07","options":[{"value":"do_not_disturb","label":"Phone/notifications off — no incoming signals"},{"value":"headphones","label":"Headphones on (even without music) — visual signal to others"},{"value":"location","label":"Being somewhere people don't expect me (different room, cafe)"},{"value":"time_blocks","label":"Scheduled 'no meeting' blocks communicated to others"},{"value":"written_notes","label":"Writing where I am before I get interrupted so I can return"}],"skippable":true,"meta_profiling":"Practical coping strategies indicate someone who has had to figure this out the hard way.","dimension":"neurodivergent.focus_protection","why_this_matters":"AI can suggest these strategies proactively when you start deep work sessions."},{"id":"t5_q08","tier":5,"tier_name":"Neurodivergent Profile","question":"Someone doesn't respond to your message for 3 hours. You...","type":"select","options":[{"value":"dont_notice","label":"Don't notice or think about it until I see the reply","maps_to":{"dimension":"neurodivergent.rejection_sensitivity","value":"low"}},{"value":"mild_wonder","label":"Mildly wonder what's up, but it doesn't stick","maps_to":{"dimension":"neurodivergent.rejection_sensitivity","value":"moderate"}},{"value":"replay_message","label":"Start replaying the message — did I say something wrong?","maps_to":{"dimension":"neurodivergent.rejection_sensitivity","value":"elevated"}},{"value":"assume_negative","label":"Assume they're upset with me or I messed up — strong gut feeling","maps_to":{"dimension":"neurodivergent.rejection_sensitivity","value":"high"},"triggers":["t5_q08a"]}],"skippable":true,"meta_profiling":"Rejection Sensitive Dysphoria is common with ADHD. The intensity of negative assumption vs reality is the key signal. Note if they add context or excuses in their answer.","dimension":"neurodivergent.rejection_sensitivity","why_this_matters":"AI can frame feedback carefully and avoid phrasing that could be misread as rejection or disapproval."},{"id":"t5_q08a","tier":5,"tier_name":"Neurodivergent Profile","question":"When you get critical feedback, even constructive, your first physical reaction is often...","type":"select","is_followup":true,"parent_question":"t5_q08","options":[{"value":"gut_drop","label":"A gut drop — physical feeling of dread or shame before I even process the content"},{"value":"flush_defensive","label":"Flush of defensiveness — my first instinct is to explain or justify"},{"value":"shut_down","label":"Shut down — I need time before I can engage with it"},{"value":"fine","label":"Fine actually — the first answer was about silence, not criticism specifically"}],"skippable":true,"meta_profiling":"Physical/somatic responses to feedback indicate RSD specifically, not just general sensitivity.","dimension":"neurodivergent.rsd","why_this_matters":"AI adjusts critique delivery — leading with what works before what doesn't, using 'I noticed' framing over 'you did wrong'."},{"id":"t5_q09","tier":5,"tier_name":"Neurodivergent Profile","question":"Around new people or in professional settings, how much do you filter your natural behavior?","type":"spectrum","spectrum":{"min":1,"max":5,"min_label":"I'm the same everywhere — what you see is what you get","max_label":"I perform a 'professional version' — exhausting but feels necessary","mid_label":"I adjust somewhat — normal code-switching"},"skippable":true,"meta_profiling":"High masking scores combined with other neurodivergent indicators = likely masking ADHD or autism. Exhaustion from masking is a real cost AI should acknowledge.","dimension":"neurodivergent.masking","why_this_matters":"AI can be a place where you don't have to mask — knowing this, it won't police your informal language or assume you need professional tone."},{"id":"t5_q10","tier":5,"tier_name":"Neurodivergent Profile","question":"When something unexpected ruins your plan — your calendar changes, a task goes sideways, someone cancels — your gut reaction is...","type":"scenario","options":[{"value":"adapt_easily","label":"Adapt easily — I pivot and figure it out","maps_to":{"dimension":"neurodivergent.emotional_regulation","value":"flexible"}},{"value":"annoyed_recovers","label":"Briefly annoyed, recover within 30 minutes","maps_to":{"dimension":"neurodivergent.emotional_regulation","value":"moderate"}},{"value":"disrupted_hours","label":"Disrupted for a few hours — the day feels 'ruined' even if logically it isn't","maps_to":{"dimension":"neurodivergent.emotional_regulation","value":"elevated"}},{"value":"full_dysregulation","label":"Full emotional reaction that's hard to control — intensity feels disproportionate and I know it","maps_to":{"dimension":"neurodivergent.emotional_regulation","value":"dysregulated"},"triggers":["t5_q10a"]}],"skippable":true,"meta_profiling":"The qualifier 'I know it' in the last option is important — it signals self-awareness about disproportionality, which is common in ADHD emotional dysregulation.","dimension":"neurodivergent.emotional_regulation","why_this_matters":"AI can build in 'disruption buffers' in planning and avoid scheduling back-to-back critical tasks where one failure cascades."},{"id":"t5_q10a","tier":5,"tier_name":"Neurodivergent Profile","question":"What helps you recover when emotions are running hot?","type":"multi_select","is_followup":true,"parent_question":"t5_q10","options":[{"value":"movement","label":"Physical movement — walk, exercise, anything that burns it off"},{"value":"alone_time","label":"Being alone until it passes — no input"},{"value":"talk_it_out","label":"Talking to someone (or writing it out)"},{"value":"sleep","label":"Sleep or rest — it's usually better the next day"},{"value":"distraction","label":"Total distraction — TV, game, something absorbing"},{"value":"nothing","label":"Nothing consistent — I just have to wait it out"}],"skippable":true,"meta_profiling":"Regulation strategies reveal how developed their coping toolkit is.","dimension":"neurodivergent.regulation_strategies","why_this_matters":"AI can suggest these strategies proactively when it detects stress signals in conversation."},{"id":"t5_q11","tier":5,"tier_name":"Neurodivergent Profile","question":"When you're thinking hard, excited, or deep in concentration — your body tends to...","type":"multi_select","options":[{"value":"leg_bounce","label":"Bounce or tap my leg","maps_to":{"dimension":"neurodivergent.stimming","value":"motor"}},{"value":"fidget_object","label":"Fidget with something — pen, ring, phone","maps_to":{"dimension":"neurodivergent.stimming","value":"object"}},{"value":"pace_move","label":"Pace or need to move around","maps_to":{"dimension":"neurodivergent.stimming","value":"vestibular"}},{"value":"sound","label":"Make sounds — hum, click, mutter to myself","maps_to":{"dimension":"neurodivergent.stimming","value":"auditory"}},{"value":"still","label":"Stay pretty still — no noticeable movement patterns","maps_to":{"dimension":"neurodivergent.stimming","value":"absent"}},{"value":"not_aware","label":"I'm not usually aware of what my body is doing","maps_to":{"dimension":"neurodivergent.body_awareness","value":"low"}}],"skippable":true,"meta_profiling":"Stimming awareness is a direct indicator of sensory/nervous system difference. Note if they express any shame in their response.","dimension":"neurodivergent.stimming","why_this_matters":"Confirms sensory processing patterns and helps AI understand that movement-friendly work setups may be beneficial."},{"id":"t5_q12","tier":5,"tier_name":"Neurodivergent Profile","question":"Topics or domains where you can talk for hours without getting bored — list them (or describe)","type":"open_text","placeholder":"E.g. 'mechanical keyboards, Roman history, fermentation, Rust programming, urban planning...'","skippable":true,"meta_profiling":"The specificity and depth of their answer reveals how developed their special interests are. Multiple specific topics vs one deep one vs vague answers all differ meaningfully.","dimension":"neurodivergent.special_interests","why_this_matters":"AI can use these as engagement hooks, learning metaphors, and dopamine boosters when you need motivation for other tasks."},{"id":"t5_q13","tier":5,"tier_name":"Neurodivergent Profile","question":"Your natural sleep schedule, if you had zero obligations, would be...","type":"select","options":[{"value":"early_riser","label":"Early to bed, early to rise — I'm naturally a morning person","maps_to":{"dimension":"neurodivergent.sleep_chronotype","value":"morning"}},{"value":"conventional","label":"Roughly conventional — 11pm-7am feels natural","maps_to":{"dimension":"neurodivergent.sleep_chronotype","value":"intermediate"}},{"value":"night_owl","label":"Night owl — I come alive at 11pm and hate mornings","maps_to":{"dimension":"neurodivergent.sleep_chronotype","value":"evening"}},{"value":"extreme_night","label":"Extreme — I'd naturally sleep 3am-11am if I could","maps_to":{"dimension":"neurodivergent.sleep_chronotype","value":"extreme_evening"}},{"value":"irregular","label":"No consistent pattern — it shifts around","maps_to":{"dimension":"neurodivergent.sleep_chronotype","value":"irregular"}}],"skippable":true,"meta_profiling":"Delayed sleep phase is more common in ADHD. Irregular pattern can indicate either ADHD or high stress.","dimension":"neurodivergent.sleep_chronotype","why_this_matters":"AI adapts scheduling recommendations and peak-hour suggestions to your actual biology, not societal defaults."},{"id":"t5_q14","tier":5,"tier_name":"Neurodivergent Profile","question":"Which of these actually help YOU work better? Select everything that's genuinely useful.","type":"multi_select","options":[{"value":"body_double","label":"Body doubling — someone present (physical or virtual)","maps_to":{"dimension":"neurodivergent.adhd_adaptations","value":"body_doubling"}},{"value":"timers_visible","label":"Visible countdown timers during work","maps_to":{"dimension":"neurodivergent.adhd_adaptations","value":"timers"}},{"value":"music_focus","label":"Specific music (lo-fi, binaural beats, brown noise)","maps_to":{"dimension":"neurodivergent.adhd_adaptations","value":"auditory_anchor"}},{"value":"movement_breaks","label":"Scheduled movement breaks every 20-30 min","maps_to":{"dimension":"neurodivergent.adhd_adaptations","value":"movement"}},{"value":"visual_progress","label":"Seeing progress visually — task lists with checkboxes, progress bars","maps_to":{"dimension":"neurodivergent.adhd_adaptations","value":"visual_progress"}},{"value":"hard_deadlines","label":"Hard external deadlines (self-imposed don't work)","maps_to":{"dimension":"neurodivergent.adhd_adaptations","value":"external_deadlines"}},{"value":"novelty","label":"Novelty and variety — switching between tasks keeps me engaged","maps_to":{"dimension":"neurodivergent.adhd_adaptations","value":"novelty"}},{"value":"single_priority","label":"Being given ONE thing to focus on — too many options paralyzes","maps_to":{"dimension":"neurodivergent.adhd_adaptations","value":"single_priority"}},{"value":"scripted_starts","label":"Scripted 'getting started' rituals that remove decisions","maps_to":{"dimension":"neurodivergent.adhd_adaptations","value":"rituals"}}],"skippable":true,"meta_profiling":"This is the direct adaptation inventory — selections here directly configure AI behavior. Note any contradictions with previous answers (e.g., novelty + single priority both selected = context-dependent).","dimension":"neurodivergent.adhd_adaptations","why_this_matters":"These become the actual settings AI uses to structure how it helps you — directly configures output style and interaction patterns."},{"id":"t5_q15","tier":5,"tier_name":"Neurodivergent Profile","question":"Right now, your energy reserves feel like...","type":"select","options":[{"value":"full","label":"Full — I feel like myself, motivated, able to take on things","maps_to":{"dimension":"neurodivergent.burnout_level","value":"low"}},{"value":"running_on_fumes","label":"Running on fumes — I'm functional but everything takes more effort","maps_to":{"dimension":"neurodivergent.burnout_level","value":"moderate"}},{"value":"depleted","label":"Depleted — I'm pushing through but not sustainably","maps_to":{"dimension":"neurodivergent.burnout_level","value":"elevated"},"triggers":["t5_q15a"]},{"value":"burnt_out","label":"Burnt out — basic things feel huge, I've lost the 'want to'","maps_to":{"dimension":"neurodivergent.burnout_level","value":"high"},"triggers":["t5_q15a"]}],"skippable":true,"meta_profiling":"Burnout self-awareness is important. Note if they answer matter-of-factly vs with deflection. High burnout + high masking = significant risk.","dimension":"neurodivergent.burnout_level","why_this_matters":"AI adjusts ambition level, task complexity, and check-in frequency based on your current reserves — not an idealized version of you."},{"id":"t5_q15a","tier":5,"tier_name":"Neurodivergent Profile","question":"Is this recent, or has it been the background state for a while?","type":"select","is_followup":true,"parent_question":"t5_q15","options":[{"value":"recent","label":"Recent — something specific happened","maps_to":{"dimension":"neurodivergent.burnout_duration","value":"acute"}},{"value":"months","label":"A few months","maps_to":{"dimension":"neurodivergent.burnout_duration","value":"subacute"}},{"value":"long_time","label":"Honestly, a long time — this is just how things are","maps_to":{"dimension":"neurodivergent.burnout_duration","value":"chronic"}}],"skippable":true,"meta_profiling":"Chronic burnout requires AI to actively push back on overcommitment, not just accommodate it.","dimension":"neurodivergent.burnout_duration","why_this_matters":"Chronic burnout changes the whole approach — AI prioritizes recovery and sustainability over productivity."},{"id":"t5_q16","tier":5,"tier_name":"Neurodivergent Profile","question":"Anything else about how your brain works that you'd want AI to know? No need for labels — just describe.","type":"open_text","placeholder":"E.g. 'I need instructions in writing, not spoken', 'I work much better at night', 'sensory stuff with certain textures', 'I'm autistic and prefer direct communication', anything...","skippable":true,"meta_profiling":"Open text here catches everything the structured questions miss. Also reveals self-narrative and identity around neurodivergence — matter-of-fact vs careful framing says a lot.","dimension":"neurodivergent.freeform","why_this_matters":"You know your brain better than any question bank does. This is your override field."}]`),r={tier:Y,tier_name:H,tier_intro:E,tier_complete:L,questions:z},R=6,M="Domain Expertise",F="What's your thing? This section maps your actual knowledge — not your job title. AI becomes dramatically more useful when it knows your real depth in a domain rather than guessing from context. 4-6 minutes.",O={headline:"Expertise map built.",body:"AI now knows where you're a practitioner vs a learner — and the gap between those two requires very different responses. It won't explain what you already know, and it'll flag when it's reaching the edges of your domain."},B=JSON.parse(`[{"id":"t6_q01","tier":6,"tier_name":"Domain Expertise","question":"If someone asked 'what's your thing?' — you'd say...","type":"open_text","placeholder":"E.g. 'I build web apps', 'I do financial modeling', 'I design brand identities', 'I train athletes', 'I write marketing copy'...","skippable":false,"meta_profiling":"Specificity is everything here. 'Software' vs 'distributed systems in Go' vs 'TypeScript full-stack with Supabase' — each is a different expertise depth signal. Note if they define themselves by tools, outcomes, or industry.","dimension":"expertise.primary_domain","why_this_matters":"This is the anchor for everything else — AI calibrates explanation depth, vocabulary, and domain-specific knowledge from this single answer."},{"id":"t6_q02","tier":6,"tier_name":"Domain Expertise","question":"In your main area, where are you honestly?","type":"spectrum","spectrum":{"min":1,"max":6,"min_label":"Actively learning the basics","max_label":"Could teach advanced courses, known as a reference in my field","steps":[{"value":1,"label":"Learning the basics"},{"value":2,"label":"Functional — can do the work with guidance"},{"value":3,"label":"Solid — confident and independent"},{"value":4,"label":"Senior — I handle complex edge cases, I mentor others"},{"value":5,"label":"Expert — I've built things, solved novel problems, seen the failure modes"},{"value":6,"label":"Authority — I set direction, I'm who people call"}]},"skippable":false,"meta_profiling":"Most people underrate themselves by 1 level. If they describe specific failure modes or edge cases in their follow-ups, weight their actual answer up. Dunning-Kruger runs both ways.","dimension":"expertise.primary_depth","why_this_matters":"A level 2 developer and a level 5 developer asking 'how do I fix this bug' need entirely different responses."},{"id":"t6_q03","tier":6,"tier_name":"Domain Expertise","question":"How long have you been in your field?","type":"select","options":[{"value":"under_1","label":"Less than 1 year","maps_to":{"dimension":"expertise.years","value":"0-1"}},{"value":"1_to_3","label":"1-3 years","maps_to":{"dimension":"expertise.years","value":"1-3"}},{"value":"3_to_7","label":"3-7 years","maps_to":{"dimension":"expertise.years","value":"3-7"}},{"value":"7_to_15","label":"7-15 years","maps_to":{"dimension":"expertise.years","value":"7-15"}},{"value":"over_15","label":"15+ years","maps_to":{"dimension":"expertise.years","value":"15+"}}],"skippable":false,"meta_profiling":"Cross-reference with self-reported depth — 15 years + level 3 depth = probably humble/burnt-out. 2 years + level 5 = either exceptional or over-confident.","dimension":"expertise.years","why_this_matters":"Years in field informs what tacit knowledge AI can assume — someone with 10 years doesn't need first-principles explanations."},{"id":"t6_q04","tier":6,"tier_name":"Domain Expertise","question":"Other areas where you're surprisingly knowledgeable — not your job, but where you know more than most people","type":"multi_select","options":[{"value":"software_dev","label":"Software development / programming","maps_to":{"dimension":"expertise.secondary","value":"software"},"triggers":["t6_q04_dev"]},{"value":"data_analytics","label":"Data, analytics, SQL, statistics","maps_to":{"dimension":"expertise.secondary","value":"data"}},{"value":"product_design","label":"Product design / UX","maps_to":{"dimension":"expertise.secondary","value":"product_design"}},{"value":"marketing","label":"Marketing, growth, copywriting","maps_to":{"dimension":"expertise.secondary","value":"marketing"}},{"value":"finance_investing","label":"Finance, accounting, investing","maps_to":{"dimension":"expertise.secondary","value":"finance"}},{"value":"sales","label":"Sales, negotiation, deals","maps_to":{"dimension":"expertise.secondary","value":"sales"}},{"value":"operations","label":"Operations, process, systems thinking","maps_to":{"dimension":"expertise.secondary","value":"operations"}},{"value":"science_research","label":"Science, research methodology","maps_to":{"dimension":"expertise.secondary","value":"science"}},{"value":"hardware_engineering","label":"Hardware, electronics, mechanical engineering","maps_to":{"dimension":"expertise.secondary","value":"hardware"}},{"value":"health_medicine","label":"Health, nutrition, medicine (non-professionally)","maps_to":{"dimension":"expertise.secondary","value":"health"}},{"value":"legal_compliance","label":"Law, compliance, regulations","maps_to":{"dimension":"expertise.secondary","value":"legal"}},{"value":"creative_arts","label":"Creative arts — music, writing, visual, film","maps_to":{"dimension":"expertise.secondary","value":"creative"}},{"value":"other","label":"Something else","triggers":["t6_q04_other"]}],"skippable":true,"meta_profiling":"T-shaped vs I-shaped vs generalist emerges here. Multiple secondary domains + senior primary = renaissance type. Note if they hesitate (hedges like 'a bit' or 'sort of').","dimension":"expertise.secondary_domains","why_this_matters":"Cross-domain knowledge enables AI to use analogies and connections that land with you — and to not over-explain areas you already understand."},{"id":"t6_q04_dev","tier":6,"tier_name":"Domain Expertise","question":"Your daily tools and technologies — check everything you use regularly","type":"multi_select","is_followup":true,"parent_question":"t6_q04","options":[{"value":"javascript","label":"JavaScript / TypeScript","maps_to":{"dimension":"expertise.tech_stack","value":"js_ts"}},{"value":"python","label":"Python","maps_to":{"dimension":"expertise.tech_stack","value":"python"}},{"value":"rust","label":"Rust","maps_to":{"dimension":"expertise.tech_stack","value":"rust"}},{"value":"go","label":"Go","maps_to":{"dimension":"expertise.tech_stack","value":"go"}},{"value":"java_kotlin","label":"Java / Kotlin","maps_to":{"dimension":"expertise.tech_stack","value":"jvm"}},{"value":"csharp","label":"C# / .NET","maps_to":{"dimension":"expertise.tech_stack","value":"dotnet"}},{"value":"swift","label":"Swift / iOS","maps_to":{"dimension":"expertise.tech_stack","value":"ios"}},{"value":"react","label":"React / Next.js","maps_to":{"dimension":"expertise.tech_stack","value":"react"}},{"value":"svelte","label":"Svelte / SvelteKit","maps_to":{"dimension":"expertise.tech_stack","value":"svelte"}},{"value":"vue","label":"Vue / Nuxt","maps_to":{"dimension":"expertise.tech_stack","value":"vue"}},{"value":"databases_sql","label":"SQL databases (PostgreSQL, MySQL, SQLite)","maps_to":{"dimension":"expertise.tech_stack","value":"sql"}},{"value":"databases_nosql","label":"NoSQL (MongoDB, Redis, DynamoDB)","maps_to":{"dimension":"expertise.tech_stack","value":"nosql"}},{"value":"cloud","label":"Cloud (AWS, GCP, Azure)","maps_to":{"dimension":"expertise.tech_stack","value":"cloud"}},{"value":"devops","label":"DevOps / CI/CD / Docker / K8s","maps_to":{"dimension":"expertise.tech_stack","value":"devops"}},{"value":"mobile","label":"Mobile (React Native, Flutter)","maps_to":{"dimension":"expertise.tech_stack","value":"mobile"}},{"value":"ai_ml","label":"AI/ML (PyTorch, TensorFlow, LangChain)","maps_to":{"dimension":"expertise.tech_stack","value":"ai_ml"}}],"skippable":true,"meta_profiling":"Stack breadth vs depth tradeoff visible here. Full-stack + DevOps + AI = generalist engineer. TypeScript only = frontend specialist. Note if they include unfamiliar tools — good conversation starter.","dimension":"expertise.tech_stack","why_this_matters":"AI defaults to your stack for code examples, tool recommendations, and framework-specific advice."},{"id":"t6_q04_other","tier":6,"tier_name":"Domain Expertise","question":"What's the surprising area you know well?","type":"open_text","is_followup":true,"parent_question":"t6_q04","placeholder":"E.g. 'Byzantine history', 'fermentation science', 'property law', 'automotive mechanics'...","skippable":true,"meta_profiling":"Specificity here is a richness signal. The more niche and precise, the more authentic the claim.","dimension":"expertise.secondary_other","why_this_matters":"Unexpected expertise domains become powerful analogy bridges for AI to use."},{"id":"t6_q05","tier":6,"tier_name":"Domain Expertise","question":"How fast do you pick up new tools or skills within your domain?","type":"select","options":[{"value":"slow_deliberate","label":"Slow and deliberate — I need time to understand something properly before using it","maps_to":{"dimension":"expertise.learning_velocity","value":"deliberate"}},{"value":"steady","label":"Steady — I pick things up at a normal pace with documentation and practice","maps_to":{"dimension":"expertise.learning_velocity","value":"steady"}},{"value":"fast","label":"Fast — I can usually get functional with a new tool in hours, not days","maps_to":{"dimension":"expertise.learning_velocity","value":"fast"}},{"value":"very_fast","label":"Very fast within my domain — I pattern-match to what I already know instantly","maps_to":{"dimension":"expertise.learning_velocity","value":"expert_transfer"}}],"skippable":true,"meta_profiling":"Expert transfer is the real signal — someone who says 'pattern match to what I know' is describing transfer learning, which is a genuine expertise indicator.","dimension":"expertise.learning_velocity","why_this_matters":"Affects how AI introduces new tools — quick overview vs detailed tutorial vs just the diff from what you know."},{"id":"t6_q06","tier":6,"tier_name":"Domain Expertise","question":"How current is your knowledge right now?","type":"select","options":[{"value":"cutting_edge","label":"Cutting edge — I follow the field closely, I know what came out this month","maps_to":{"dimension":"expertise.knowledge_currency","value":"current"}},{"value":"recent","label":"Recent — maybe 6-12 months behind the bleeding edge, but solid","maps_to":{"dimension":"expertise.knowledge_currency","value":"recent"}},{"value":"stable","label":"Stable — my core knowledge is sound but I'm not chasing every new thing","maps_to":{"dimension":"expertise.knowledge_currency","value":"stable"}},{"value":"dated","label":"A bit dated — I know I need to catch up on some things","maps_to":{"dimension":"expertise.knowledge_currency","value":"stale"}}],"skippable":true,"meta_profiling":"Self-awareness about knowledge currency is itself an expertise signal — junior people often don't know what they're missing.","dimension":"expertise.knowledge_currency","why_this_matters":"AI can flag when it's about to mention something you likely already know vs something you might have missed."},{"id":"t6_q07","tier":6,"tier_name":"Domain Expertise","question":"Industries you've actually worked in (not just studied)","type":"multi_select","options":[{"value":"tech_software","label":"Tech / Software","maps_to":{"dimension":"expertise.industries","value":"tech"}},{"value":"finance_banking","label":"Finance / Banking / FinTech","maps_to":{"dimension":"expertise.industries","value":"finance"}},{"value":"healthcare","label":"Healthcare / MedTech / Pharma","maps_to":{"dimension":"expertise.industries","value":"healthcare"}},{"value":"ecommerce_retail","label":"E-commerce / Retail","maps_to":{"dimension":"expertise.industries","value":"ecommerce"}},{"value":"manufacturing","label":"Manufacturing / Industrial","maps_to":{"dimension":"expertise.industries","value":"manufacturing"}},{"value":"education","label":"Education / EdTech","maps_to":{"dimension":"expertise.industries","value":"education"}},{"value":"media_creative","label":"Media / Creative / Entertainment","maps_to":{"dimension":"expertise.industries","value":"media"}},{"value":"agency_consulting","label":"Agency / Consulting / Services","maps_to":{"dimension":"expertise.industries","value":"consulting"}},{"value":"startup","label":"Startup / Early-stage","maps_to":{"dimension":"expertise.industries","value":"startup"}},{"value":"enterprise","label":"Enterprise / Large corp","maps_to":{"dimension":"expertise.industries","value":"enterprise"}},{"value":"government_ngo","label":"Government / NGO / Nonprofit","maps_to":{"dimension":"expertise.industries","value":"public_sector"}},{"value":"real_estate","label":"Real estate / Construction","maps_to":{"dimension":"expertise.industries","value":"real_estate"}},{"value":"logistics","label":"Logistics / Supply chain","maps_to":{"dimension":"expertise.industries","value":"logistics"}}],"skippable":true,"meta_profiling":"Breadth across sectors vs depth in one. Startup + enterprise is a common pair that reveals adaptability. Note if industries cluster around a theme (all B2B, all consumer, etc).","dimension":"expertise.industries","why_this_matters":"Industry context shapes which examples land, what regulations to mention, and what assumptions are safe."},{"id":"t6_q08","tier":6,"tier_name":"Domain Expertise","question":"Could you explain your main expertise to a smart person who knows nothing about it — and make it stick?","type":"select","options":[{"value":"yes_easy","label":"Yes, I do this regularly — I'm good at translating complex things","maps_to":{"dimension":"expertise.teaching_ability","value":"strong"}},{"value":"yes_with_effort","label":"Yes, but it takes effort — I have to really think about the framing","maps_to":{"dimension":"expertise.teaching_ability","value":"moderate"}},{"value":"basic_yes","label":"The basics yes, but the nuanced stuff is hard to convey without shared context","maps_to":{"dimension":"expertise.teaching_ability","value":"partial"}},{"value":"no","label":"Honestly not well — I'm better at doing it than explaining it","maps_to":{"dimension":"expertise.teaching_ability","value":"low"}}],"skippable":true,"meta_profiling":"Teaching ability correlates with expertise depth (Feynman technique — if you can't explain it, you don't fully understand it). But some experts are genuinely poor teachers. Note the gap.","dimension":"expertise.teaching_ability","why_this_matters":"Tells AI whether to explain concepts from fundamentals or just reference them by name — and whether to offer to explain the 'why' behind things."},{"id":"t6_q09","tier":6,"tier_name":"Domain Expertise","question":"Right now, are you more often the person teaching or the person learning?","type":"spectrum","spectrum":{"min":1,"max":5,"min_label":"Almost always learning — I'm newer and absorbing everything","max_label":"Almost always teaching — I'm the reference point for others","mid_label":"Both — learning in some areas, teaching in others"},"skippable":true,"meta_profiling":"Mentorship position reveals career stage and confidence better than years-of-experience. Note if they say 'both' and whether it sounds confident or uncertain.","dimension":"expertise.mentorship_position","why_this_matters":"AI adjusts whether to offer explanations proactively or assume you'll ask when you need them."},{"id":"t6_q10","tier":6,"tier_name":"Domain Expertise","question":"Do insights from other fields actually influence your main work?","type":"select","options":[{"value":"yes_constantly","label":"Yes — I actively borrow from other domains, it's part of how I think","maps_to":{"dimension":"expertise.cross_pollination","value":"high"}},{"value":"sometimes","label":"Sometimes — I'll notice a parallel and use it, but not systematically","maps_to":{"dimension":"expertise.cross_pollination","value":"moderate"}},{"value":"rarely","label":"Rarely — I tend to stay within the established approaches of my field","maps_to":{"dimension":"expertise.cross_pollination","value":"low"}}],"skippable":true,"meta_profiling":"High cross-pollination correlates with interdisciplinary thinking, creativity, and often innovation. Note what fields they mention if they expand.","dimension":"expertise.cross_pollination","why_this_matters":"High cross-pollination thinkers appreciate when AI draws analogies from unexpected domains — it's how they think, not a distraction."},{"id":"t6_q11","tier":6,"tier_name":"Domain Expertise","question":"In your domain — what do you WISH you knew better?","type":"open_text","placeholder":"Be specific. Not 'I want to learn more' — what's the actual gap that limits you?","skippable":true,"meta_profiling":"Specific articulation of gaps is itself an expertise indicator. Vague answers ('I want to know more about AI') vs precise ones ('I don't fully understand transformer attention mechanisms') reveal real depth.","dimension":"expertise.known_gaps","why_this_matters":"AI can proactively offer depth in these areas and flag when they're relevant to what you're working on."},{"id":"t6_q12","tier":6,"tier_name":"Domain Expertise","question":"When you're working in your domain, what's your most common mode?","type":"select","options":[{"value":"building","label":"Building — creating things, writing code, making deliverables","maps_to":{"dimension":"expertise.work_mode","value":"builder"}},{"value":"analyzing","label":"Analyzing — researching, evaluating, making sense of complex information","maps_to":{"dimension":"expertise.work_mode","value":"analyst"}},{"value":"communicating","label":"Communicating — writing, presenting, persuading, teaching","maps_to":{"dimension":"expertise.work_mode","value":"communicator"}},{"value":"leading","label":"Leading — coordinating, deciding, unblocking others","maps_to":{"dimension":"expertise.work_mode","value":"leader"}},{"value":"mixed","label":"Mixed — my role spans several of these","maps_to":{"dimension":"expertise.work_mode","value":"generalist"}}],"skippable":true,"meta_profiling":"Work mode shapes what AI outputs are actually useful — code vs documents vs decision frameworks vs presentations.","dimension":"expertise.work_mode","why_this_matters":"A builder wants working code. An analyst wants structured frameworks. A communicator wants polished copy. Same question, different right answers."},{"id":"t6_q13","tier":6,"tier_name":"Domain Expertise","question":"Your expertise in one sentence — as you'd describe it to a smart, curious person at a dinner party","type":"open_text","placeholder":"Not your job title. What do you actually DO and why does it matter?","skippable":true,"meta_profiling":"The dinner party framing removes professional defensiveness. Note: clarity, specificity, and whether they lead with impact vs process vs identity.","dimension":"expertise.self_narrative","why_this_matters":"This becomes how AI introduces and frames your expertise when helping with personal branding, bios, pitches, or outreach."}]`),l={tier:R,tier_name:M,tier_intro:F,tier_complete:O,questions:B},G=7,V="Life Context",$="This is the most optional section in Meport. Every question here is skippable. We're asking because life context makes AI recommendations actually relevant — tools that cost $200/month hit differently at different life stages, and 'just put in 2 extra hours' means different things to different people. Share only what you're comfortable with.",J={headline:"Life context mapped.",body:"Most AI acts like everyone has unlimited time, money, and energy. Yours doesn't anymore. Recommendations will now reflect where you actually are, not an idealized version of you that has everything figured out. That's a rare thing."},U=JSON.parse(`[{"id":"t7_q01","tier":7,"tier_name":"Life Context","question":"Which of these best describes where you are right now?","type":"select","options":[{"value":"student_early","label":"Student or early career — building foundations, figuring it out","maps_to":{"dimension":"life.stage","value":"early_career"}},{"value":"established_climbing","label":"Established and climbing — I know what I'm doing, pushing for the next level","maps_to":{"dimension":"life.stage","value":"growth"}},{"value":"pivot","label":"In transition — changing direction, reinventing, or starting something new","maps_to":{"dimension":"life.stage","value":"transition"},"triggers":["t7_q01a"]},{"value":"building_business","label":"Building a business or going independent — entrepreneurial mode","maps_to":{"dimension":"life.stage","value":"entrepreneurial"}},{"value":"senior_optimizing","label":"Senior and optimizing — accomplished, now focused on leverage and impact","maps_to":{"dimension":"life.stage","value":"senior"}},{"value":"life_first","label":"Life-first right now — work is supporting something bigger (family, health, personal goal)","maps_to":{"dimension":"life.stage","value":"life_priority"}}],"skippable":true,"meta_profiling":"Stage affects ambition calibration, risk tolerance framing, and what counts as a 'win'. Note if their tone matches their stated stage — someone saying 'building a business' with low energy may be struggling.","dimension":"life.stage","why_this_matters":"Life stage changes what 'good advice' looks like completely — a student and a senior executive have opposite optimal moves in most situations."},{"id":"t7_q01a","tier":7,"tier_name":"Life Context","question":"What are you transitioning toward?","type":"open_text","is_followup":true,"parent_question":"t7_q01","placeholder":"E.g. 'leaving corporate for freelance', 'career change from finance to tech', 'returning to work after time off'...","skippable":true,"meta_profiling":"Clarity of direction during transition is itself a signal — very clear destination vs fuzzy searching vs exploring are different situations.","dimension":"life.transition_direction","why_this_matters":"Transition context changes risk tolerance — AI will frame options differently for someone with a clear target vs someone still figuring it out."},{"id":"t7_q02","tier":7,"tier_name":"Life Context","question":"When AI suggests a paid tool, course, or resource, what framing actually works for you?","type":"select","options":[{"value":"show_free_first","label":"Show me the free version first — I'll upgrade if it's worth it","maps_to":{"dimension":"life.financial_context","value":"cost_conscious"}},{"value":"roi_framing","label":"Tell me the ROI — if it saves time or makes money, I'm interested in the cost","maps_to":{"dimension":"life.financial_context","value":"roi_focused"}},{"value":"best_option","label":"Just tell me the best option — I'll decide whether to pay","maps_to":{"dimension":"life.financial_context","value":"flexible"}},{"value":"skip_paid","label":"Skip paid recommendations entirely for now — I'm watching every expense","maps_to":{"dimension":"life.financial_context","value":"constrained"}}],"skippable":true,"meta_profiling":"This reveals financial comfort without asking income. 'Skip paid entirely' is a real constraint. 'Just best option' = financially comfortable or delegating the decision.","dimension":"life.financial_context","why_this_matters":"Calibrates whether AI leads with free alternatives, adds cost context, or skips price discussion when recommending tools."},{"id":"t7_q03","tier":7,"tier_name":"Life Context","question":"Your household situation (affects time availability and what's realistic to suggest)","type":"select","options":[{"value":"solo","label":"Living alone — full flexibility","maps_to":{"dimension":"life.household","value":"solo"}},{"value":"partner_no_kids","label":"Partner, no kids — shared space, some coordination","maps_to":{"dimension":"life.household","value":"couple"}},{"value":"partner_kids","label":"Partner + kids — family coordination, less free time","maps_to":{"dimension":"life.household","value":"family"}},{"value":"single_parent","label":"Single parent — primary caregiver, time is scarce","maps_to":{"dimension":"life.household","value":"single_parent"}},{"value":"roommates","label":"With roommates — shared space, some noise/schedule constraints","maps_to":{"dimension":"life.household","value":"shared"}},{"value":"family_home","label":"Family home — living with parents or extended family","maps_to":{"dimension":"life.household","value":"family_home"}}],"skippable":true,"meta_profiling":"Household situation is the single best predictor of discretionary time and flexibility. Single parent is the most constrained; solo is the most flexible.","dimension":"life.household","why_this_matters":"'Do this every morning for 2 hours' lands very differently based on who's home with you."},{"id":"t7_q04","tier":7,"tier_name":"Life Context","question":"On a typical weekday, how many hours do you genuinely have for yourself — not work, not obligations?","type":"spectrum","spectrum":{"min":1,"max":5,"min_label":"Almost none — most days are fully claimed","max_label":"3+ hours — I have real flexibility","steps":[{"value":1,"label":"30 min or less"},{"value":2,"label":"About 1 hour"},{"value":3,"label":"1-2 hours"},{"value":4,"label":"2-3 hours"},{"value":5,"label":"3+ hours"}]},"skippable":true,"meta_profiling":"Cross with household situation and life stage. High available time + family with kids = likely not calibrated accurately. Low available time + solo = burnout signal.","dimension":"life.discretionary_time","why_this_matters":"AI won't recommend 90-minute daily routines to someone with 30 free minutes. Everything gets scaled to actual capacity."},{"id":"t7_q05","tier":7,"tier_name":"Life Context","question":"Your top priorities right now — what's actually competing for your attention and energy?","type":"multi_select","options":[{"value":"career_growth","label":"Career growth — getting better, getting promoted, getting paid more","maps_to":{"dimension":"life.priorities","value":"career"}},{"value":"business_building","label":"Building a business — revenue, growth, customers","maps_to":{"dimension":"life.priorities","value":"business"}},{"value":"financial_stability","label":"Financial stability or recovery — paying off debt, building a buffer","maps_to":{"dimension":"life.priorities","value":"finances"}},{"value":"health_fitness","label":"Health and fitness — weight, strength, energy, longevity","maps_to":{"dimension":"life.priorities","value":"health"}},{"value":"relationships","label":"Relationships — romantic, family, friendships","maps_to":{"dimension":"life.priorities","value":"relationships"}},{"value":"learning","label":"Learning something specific — skill, domain, qualification","maps_to":{"dimension":"life.priorities","value":"learning"}},{"value":"creative_project","label":"A creative project — writing, building, making","maps_to":{"dimension":"life.priorities","value":"creative"}},{"value":"mental_health","label":"Mental health and wellbeing — stability, peace, figuring myself out","maps_to":{"dimension":"life.priorities","value":"mental_health"}},{"value":"lifestyle_design","label":"Lifestyle design — location, freedom, how I want to live","maps_to":{"dimension":"life.priorities","value":"lifestyle"}}],"skippable":true,"meta_profiling":"More than 3 priorities = either high energy + high capacity, or unrealistic. Note what's conspicuously absent (e.g. relationships never mentioned by someone who seems lonely in their messages).","dimension":"life.priorities","why_this_matters":"AI connects its advice to what actually matters to you — not generic 'be productive' advice."},{"id":"t7_q06","tier":7,"tier_name":"Life Context","question":"What's actively blocking you right now?","type":"multi_select","options":[{"value":"time","label":"Not enough time — genuinely stretched thin","maps_to":{"dimension":"life.blockers","value":"time"}},{"value":"money","label":"Financial constraints — cash limits what I can do","maps_to":{"dimension":"life.blockers","value":"money"}},{"value":"clarity","label":"Lack of clarity — not sure what to do or which direction","maps_to":{"dimension":"life.blockers","value":"clarity"}},{"value":"motivation","label":"Motivation — I know what to do, starting is the problem","maps_to":{"dimension":"life.blockers","value":"motivation"}},{"value":"skills","label":"Skills gap — there's something I need to learn first","maps_to":{"dimension":"life.blockers","value":"skills"}},{"value":"health","label":"Health — physical or mental, it's limiting what I can do","maps_to":{"dimension":"life.blockers","value":"health"}},{"value":"relationships","label":"Relationships or support — going it alone, or friction with people who matter","maps_to":{"dimension":"life.blockers","value":"social"}},{"value":"confidence","label":"Confidence or fear — I hold myself back","maps_to":{"dimension":"life.blockers","value":"confidence"}},{"value":"not_blocked","label":"Nothing major — I'm in a good flow right now","maps_to":{"dimension":"life.blockers","value":"none"}}],"skippable":true,"meta_profiling":"Most critical blockers for AI to know — this directly shapes where AI should and shouldn't push. 'Confidence' is often under-reported. Multiple structural blockers (time + money + health) = serious constraint.","dimension":"life.blockers","why_this_matters":"AI shouldn't keep suggesting things you can't do. Knowing real blockers means it suggests workarounds instead of obstacles."},{"id":"t7_q07","tier":7,"tier_name":"Life Context","question":"Where you live","type":"select","options":[{"value":"major_city_us_eu","label":"Major city (US, UK, Western Europe)","maps_to":{"dimension":"life.location_type","value":"major_western"}},{"value":"major_city_other","label":"Major city (Asia, LATAM, Eastern Europe, other)","maps_to":{"dimension":"life.location_type","value":"major_other"}},{"value":"mid_city","label":"Mid-sized city","maps_to":{"dimension":"life.location_type","value":"mid_city"}},{"value":"small_town","label":"Small town or rural area","maps_to":{"dimension":"life.location_type","value":"small_town"}},{"value":"remote_nomad","label":"Moving around / digital nomad","maps_to":{"dimension":"life.location_type","value":"nomad"}}],"skippable":true,"meta_profiling":"Location affects pricing context, service availability, timezone for collaboration, and cultural context for communication style.","dimension":"life.location_type","why_this_matters":"Affects which services exist where you are, pricing in local context, and whether remote/in-person suggestions are realistic."},{"id":"t7_q08","tier":7,"tier_name":"Life Context","question":"When you need help — with a decision, a problem, an emotional tough patch — you tend to...","type":"select","options":[{"value":"people_first","label":"Call or message someone I trust — people are my first resource","maps_to":{"dimension":"life.support_style","value":"social"}},{"value":"figure_out_alone","label":"Figure it out alone first — I process internally before involving anyone","maps_to":{"dimension":"life.support_style","value":"independent"}},{"value":"research","label":"Research it — I look for information and frameworks before deciding","maps_to":{"dimension":"life.support_style","value":"information_seeking"}},{"value":"no_ask","label":"Push through alone — I don't like asking for help","maps_to":{"dimension":"life.support_style","value":"avoidant"}},{"value":"depends","label":"Depends on the type of problem — different resources for different things","maps_to":{"dimension":"life.support_style","value":"contextual"}}],"skippable":true,"meta_profiling":"Support avoidance is worth noting — people who don't ask for help often struggle longer than necessary. AI can be a low-barrier alternative.","dimension":"life.support_style","why_this_matters":"AI adjusts whether to proactively offer support or wait to be asked — and whether to suggest professional resources early or let you lead."},{"id":"t7_q09","tier":7,"tier_name":"Life Context","question":"Overall stress level lately","type":"spectrum","spectrum":{"min":1,"max":5,"min_label":"Very low — life feels manageable right now","max_label":"Very high — I'm running on stress and trying to hold it together","mid_label":"Normal background stress — busy but okay"},"skippable":true,"meta_profiling":"High stress self-reports + ambitious goal lists = recipe for burnout AI should flag. Low stress + very high capability = good time to stretch. Note: people under-report stress.","dimension":"life.stress_level","why_this_matters":"AI dials back complexity and deadline pressure under high stress, and can push more under low stress."},{"id":"t7_q10","tier":7,"tier_name":"Life Context","question":"How's life feeling overall right now?","type":"spectrum","spectrum":{"min":1,"max":5,"min_label":"Rough — I'm in a difficult period","max_label":"Really good — things are clicking","mid_label":"Okay — not bad, not great"},"skippable":true,"meta_profiling":"Life satisfaction cross-referenced with stress is the key signal. High stress + high satisfaction = meaningful challenge. Low stress + low satisfaction = drift or depression. Note any disconnect with how they phrase other answers.","dimension":"life.satisfaction","why_this_matters":"Context for how AI frames things — different register for 'I'm doing great' vs 'I'm in a difficult period'."},{"id":"t7_q11","tier":7,"tier_name":"Life Context","question":"Are you in the middle of any major life changes?","type":"multi_select","options":[{"value":"new_job_role","label":"New job or major role change","maps_to":{"dimension":"life.transitions","value":"career_change"}},{"value":"starting_business","label":"Starting or growing a business","maps_to":{"dimension":"life.transitions","value":"entrepreneurship"}},{"value":"moving","label":"Moving — city, country, home","maps_to":{"dimension":"life.transitions","value":"relocation"}},{"value":"relationship_change","label":"Major relationship change — new, ending, marriage, divorce","maps_to":{"dimension":"life.transitions","value":"relationship"}},{"value":"family_change","label":"Family change — new child, loss, caring for someone","maps_to":{"dimension":"life.transitions","value":"family"}},{"value":"health_journey","label":"Health journey — significant change or challenge","maps_to":{"dimension":"life.transitions","value":"health"}},{"value":"financial_shift","label":"Major financial shift — up or down","maps_to":{"dimension":"life.transitions","value":"financial"}},{"value":"identity_shift","label":"Figuring out who I am / what I want — identity rework","maps_to":{"dimension":"life.transitions","value":"identity"}},{"value":"none","label":"No major changes — things are relatively stable","maps_to":{"dimension":"life.transitions","value":"stable"}}],"skippable":true,"meta_profiling":"Multiple simultaneous transitions = very high cognitive and emotional load. AI should not add complexity during this period. Identity rework is underrated — people in it are often fragile and need gentle framing.","dimension":"life.transitions","why_this_matters":"Major transitions change what 'helpful' means — AI keeps this context and doesn't assume your circumstances are static."},{"id":"t7_q12","tier":7,"tier_name":"Life Context","question":"In 2-3 years, what does success look like for you? Not professionally — personally.","type":"open_text","placeholder":"E.g. 'I've left the rat race and work 30h a week on my own terms', 'I've paid off debt and have 6 months saved', 'I've built something I'm genuinely proud of', 'I've reconnected with what makes me happy'...","skippable":true,"meta_profiling":"This is the highest-signal question in the tier. Specificity = clarity and self-knowledge. Vague = searching. Financial vs freedom vs impact vs relationships reveals deep values. Note what's NOT mentioned.","dimension":"life.personal_vision","why_this_matters":"Everything AI recommends can be filtered through this vision — 'does this move me toward or away from that future?'"},{"id":"t7_q13","tier":7,"tier_name":"Life Context","question":"Anything about your health that's relevant for AI recommendations? (completely optional)","type":"open_text","placeholder":"E.g. 'chronic back pain so I can't sit for long', 'I have PCOS and the standard diet advice doesn't apply', 'I'm in recovery so certain suggestions are off-limits', anything...","skippable":true,"meta_profiling":"What they choose to share — and HOW they phrase it — reveals comfort level with the topic. Matter-of-fact = settled. Hedged = sensitive. Note: don't pry.","dimension":"life.health_context","why_this_matters":"Prevents AI from suggesting things that would be harmful, unhelpful, or simply wrong given your actual health situation."},{"id":"t7_q14","tier":7,"tier_name":"Life Context","question":"Cultural or personal context that shapes how you think and communicate — anything you'd want AI to understand","type":"open_text","placeholder":"E.g. 'I grew up in a collectivist culture so individualist framing feels off', 'I'm a first-generation immigrant so I have a different relationship with risk', 'certain topics are sensitive in my family or cultural context'...","skippable":true,"meta_profiling":"This catches important context that question banks can't anticipate. The choice to share or skip is itself meaningful.","dimension":"life.cultural_context","why_this_matters":"AI adapts examples, framing, and assumptions to your actual cultural context — not a default Western professional one."}]`),u={tier:G,tier_name:V,tier_intro:$,tier_complete:J,questions:U},K=8,Q="AI Relationship",X="The last layer. This one's about you and AI — your history, comfort level, expectations, and where you draw the line. It directly shapes how AI behaves with you from day one. 5-7 minutes, and honestly the most interesting section.",Z={headline:"Profile complete.",body:"That's it. All 8 tiers. Your Meport profile is ready to export to any AI platform — Claude, GPT, Gemini, Cursor, whatever you use. One profile, always yours, updated as you change. Most people who build this say it's the first time AI has actually felt like it gets them. Welcome to that."},ee=JSON.parse(`[{"id":"t8_q01","tier":8,"tier_name":"AI Relationship","question":"Your relationship with AI tools so far...","type":"spectrum","spectrum":{"min":1,"max":6,"min_label":"Just starting — this might be my first real experiment","max_label":"I build AI tools or work in AI professionally","steps":[{"value":1,"label":"Just starting out"},{"value":2,"label":"Casual user — ChatGPT occasionally, nothing serious"},{"value":3,"label":"Regular user — it's part of my workflow"},{"value":4,"label":"Power user — I've customized prompts, explored different tools"},{"value":5,"label":"Advanced — I've built custom GPTs, written system prompts, integrated APIs"},{"value":6,"label":"Professional — I build AI tools or work in AI"}]},"skippable":false,"meta_profiling":"This single score calibrates every other question in this tier — a level 2 and a level 6 need completely different framing. Note how they describe their experience in phrasing.","dimension":"ai.experience_level","why_this_matters":"The foundation — AI calibrates technical depth, vocabulary, and how much it explains vs assumes based on this."},{"id":"t8_q02","tier":8,"tier_name":"AI Relationship","question":"When AI gives you an answer, you...","type":"select","options":[{"value":"trust_verify_important","label":"Trust it for most things, verify on things that actually matter","maps_to":{"dimension":"ai.trust","value":"calibrated"}},{"value":"trust_fully","label":"Usually trust it — it's generally accurate enough for my needs","maps_to":{"dimension":"ai.trust","value":"high"}},{"value":"always_verify","label":"Always verify anything important — I've been burned by confident wrong answers","maps_to":{"dimension":"ai.trust","value":"skeptical"},"triggers":["t8_q02a"]},{"value":"low_trust","label":"Generally skeptical — I use it as a starting point but don't rely on it","maps_to":{"dimension":"ai.trust","value":"low"}}],"skippable":false,"meta_profiling":"Trust calibration affects how AI presents information — whether to lead with caveats, flag uncertainty proactively, or just answer directly. Burned users need different handling.","dimension":"ai.trust","why_this_matters":"AI adjusts how confidently it delivers answers — adding uncertainty flags proactively for skeptics, staying direct for high-trust users."},{"id":"t8_q02a","tier":8,"tier_name":"AI Relationship","question":"What was the situation where AI got it confidently wrong?","type":"open_text","is_followup":true,"parent_question":"t8_q02","placeholder":"Not required — but if there's a specific pattern (code, facts, medical, legal...) it helps AI flag those areas more carefully","skippable":true,"meta_profiling":"The specificity of the failure memory reveals how much it affected their relationship with AI. Domain specificity (legal vs code) lets AI be appropriately cautious in those areas.","dimension":"ai.trust_failure","why_this_matters":"AI will proactively caveat answers in the domains where it previously failed you."},{"id":"t8_q03","tier":8,"tier_name":"AI Relationship","question":"Your ideal AI would be like a...","type":"select","options":[{"value":"tool","label":"Tool — powerful, precise, does exactly what I ask, no more","description":"No personality, no initiative — just execution","maps_to":{"dimension":"ai.relationship_model","value":"tool"}},{"value":"assistant","label":"Assistant — proactive, organized, handles details, frees me up","description":"Anticipates needs, manages tasks, keeps things on track","maps_to":{"dimension":"ai.relationship_model","value":"assistant"}},{"value":"collaborator","label":"Collaborator — a peer who builds alongside me","description":"Contributes ideas, pushes back, real co-creation","maps_to":{"dimension":"ai.relationship_model","value":"collaborator"}},{"value":"coach","label":"Coach — asks the right questions, helps me think, doesn't just give answers","description":"Guides more than executes","maps_to":{"dimension":"ai.relationship_model","value":"coach"}},{"value":"sparring_partner","label":"Sparring partner — I want pushback, challenge, devil's advocate","description":"Steel-mans alternatives, challenges assumptions","maps_to":{"dimension":"ai.relationship_model","value":"sparring_partner"}},{"value":"creative_partner","label":"Creative partner — brings ideas I wouldn't think of, surprises me","description":"Divergent thinking, unexpected angles","maps_to":{"dimension":"ai.relationship_model","value":"creative_partner"}}],"skippable":false,"meta_profiling":"This is the second highest signal in this tier after experience level. Tool vs collaborator requires fundamentally different AI behavior. Note if they pick coach/sparring despite low experience — aspirational selection.","dimension":"ai.relationship_model","why_this_matters":"This directly shapes AI's default behavior — proactivity level, whether it pushes back, how much it volunteers vs waits to be asked."},{"id":"t8_q04","tier":8,"tier_name":"AI Relationship","question":"When you're wrong about something, AI should...","type":"select","options":[{"value":"direct_correct","label":"Tell me directly — I want the truth, not cushioning","maps_to":{"dimension":"ai.correction_style","value":"direct"}},{"value":"acknowledge_then_correct","label":"Acknowledge what's right in my thinking, then correct the error","maps_to":{"dimension":"ai.correction_style","value":"balanced"}},{"value":"question_framing","label":"Ask questions that help me arrive at the correction myself","maps_to":{"dimension":"ai.correction_style","value":"socratic"}},{"value":"context_dependent","label":"Depends — small errors: just correct. Big errors: carefully.","maps_to":{"dimension":"ai.correction_style","value":"context_dependent"}}],"skippable":false,"meta_profiling":"Correction preference often differs from stated preference — people who say 'direct' sometimes react badly to direct correction. Cross-reference with rejection sensitivity from tier 5.","dimension":"ai.correction_style","why_this_matters":"Nothing breaks trust faster than an AI that corrects you in a way that feels wrong. This gets the tone right."},{"id":"t8_q05","tier":8,"tier_name":"AI Relationship","question":"AI confidently tells you something you suspect is wrong. You...","type":"scenario","options":[{"value":"push_back_immediately","label":"Push back immediately — I'll say 'I don't think that's right'","maps_to":{"dimension":"ai.hallucination_response","value":"active_challenger"}},{"value":"go_verify","label":"Go verify it first, then come back if I'm right","maps_to":{"dimension":"ai.hallucination_response","value":"verify_first"}},{"value":"note_uncertainty","label":"Note the uncertainty mentally but use it anyway unless stakes are high","maps_to":{"dimension":"ai.hallucination_response","value":"pragmatic"}},{"value":"trust_ai","label":"Probably trust the AI — it usually knows more than I do","maps_to":{"dimension":"ai.hallucination_response","value":"deferential"}}],"skippable":true,"meta_profiling":"Deferential response is the most concerning for AI safety. Pragmatic is realistic and fine. Active challenger — AI should confirm uncertainty proactively rather than wait to be challenged.","dimension":"ai.hallucination_response","why_this_matters":"AI calibrates how strongly to signal its own uncertainty — more proactive hedging for users who tend toward deference."},{"id":"t8_q06","tier":8,"tier_name":"AI Relationship","question":"AI that remembers everything about you — past conversations, preferences, mistakes, achievements — sounds...","type":"spectrum","spectrum":{"min":1,"max":5,"min_label":"Terrifying — I'd rather start fresh every time","max_label":"Ideal — that's the whole point, continuity is everything","mid_label":"Useful within limits — I want control over what it remembers"},"skippable":false,"meta_profiling":"Low scores indicate privacy-first preference — AI should be explicit about what it retains and offer easy deletion. High scores = maximize continuity features. Note if they clarify 'control' specifically.","dimension":"ai.memory_preference","why_this_matters":"Directly configures how aggressively Meport stores and uses your history — you set the dial."},{"id":"t8_q07","tier":8,"tier_name":"AI Relationship","question":"How proactive do you want AI to be?","type":"spectrum","spectrum":{"min":1,"max":5,"min_label":"Reactive only — answer when asked, don't volunteer","max_label":"Highly proactive — notice things, flag risks, suggest before I ask","steps":[{"value":1,"label":"Strictly reactive — only when I ask"},{"value":2,"label":"Mostly reactive — occasional flags on critical things"},{"value":3,"label":"Balanced — proactive on important things, reactive otherwise"},{"value":4,"label":"Proactive — I like when it notices things I might miss"},{"value":5,"label":"Highly proactive — anticipate, suggest, flag, remind"}]},"skippable":false,"meta_profiling":"Proactivity preference is one of the most important behavioral settings. Note if they answer 5 but also answered 'tool' in the role question — contradiction that needs reconciling.","dimension":"ai.proactivity","why_this_matters":"The core behavioral dial — sets whether AI waits to be asked or actively drives."},{"id":"t8_q08","tier":8,"tier_name":"AI Relationship","question":"Your ideal AI personality — what traits actually matter to you?","type":"multi_select","options":[{"value":"direct","label":"Direct — no hedging, no 'on the other hand', just the answer","maps_to":{"dimension":"ai.personality","value":"direct"}},{"value":"curious","label":"Curious — asks good questions, genuinely interested","maps_to":{"dimension":"ai.personality","value":"curious"}},{"value":"warm","label":"Warm — feels like talking to a human, not a machine","maps_to":{"dimension":"ai.personality","value":"warm"}},{"value":"dry_humor","label":"Dry humor — I appreciate wit, sarcasm, not taking itself too seriously","maps_to":{"dimension":"ai.personality","value":"dry_humor"}},{"value":"honest","label":"Radically honest — tells me what I need to hear, not what I want","maps_to":{"dimension":"ai.personality","value":"honest"}},{"value":"precise","label":"Precise — exact, careful with words, no waffle","maps_to":{"dimension":"ai.personality","value":"precise"}},{"value":"efficient","label":"Efficient — respects my time, no unnecessary words","maps_to":{"dimension":"ai.personality","value":"efficient"}},{"value":"encouraging","label":"Encouraging — recognizes effort, acknowledges progress","maps_to":{"dimension":"ai.personality","value":"encouraging"}},{"value":"neutral","label":"Neutral — no personality injection, just clean responses","maps_to":{"dimension":"ai.personality","value":"neutral"}}],"skippable":true,"meta_profiling":"Cluster patterns matter: direct + honest + efficient = no-BS preference. Warm + encouraging + curious = relationship-oriented. Neutral alone = tool mode consistent. Contradictions (warm + neutral) = needs clarification.","dimension":"ai.personality_preferences","why_this_matters":"AI adopts the tone and style that actually works for you — these traits become the behavioral filter."},{"id":"t8_q09","tier":8,"tier_name":"AI Relationship","question":"When you're having a rough day and mention it to AI, you'd prefer...","type":"select","options":[{"value":"acknowledge_move_on","label":"Brief acknowledgment, then get back to work — I don't need emotional support from AI","maps_to":{"dimension":"ai.emotional_support","value":"minimal"}},{"value":"validate_first","label":"Acknowledge it properly before we continue — feeling heard matters","maps_to":{"dimension":"ai.emotional_support","value":"moderate"}},{"value":"check_in","label":"Ask if I want to talk about it or just continue — let me choose","maps_to":{"dimension":"ai.emotional_support","value":"user_led"}},{"value":"no_comment","label":"Not comment on it at all — just answer what I asked","maps_to":{"dimension":"ai.emotional_support","value":"none"}}],"skippable":true,"meta_profiling":"This question is deceptively important — getting emotional register wrong is one of the most jarring AI failures. Note if this conflicts with their warm/neutral personality preference.","dimension":"ai.emotional_support","why_this_matters":"AI won't ignore your wellbeing or force unwanted support — it matches your actual preference here."},{"id":"t8_q10","tier":8,"tier_name":"AI Relationship","question":"Topics where AI should NOT give opinions or push a perspective, even when asked","type":"multi_select","options":[{"value":"politics","label":"Politics and governance","maps_to":{"dimension":"ai.opinion_limits","value":"politics"}},{"value":"religion","label":"Religion and spirituality","maps_to":{"dimension":"ai.opinion_limits","value":"religion"}},{"value":"personal_relationships","label":"My personal relationships — who I should be with, how I should treat people","maps_to":{"dimension":"ai.opinion_limits","value":"relationships"}},{"value":"parenting","label":"Parenting choices","maps_to":{"dimension":"ai.opinion_limits","value":"parenting"}},{"value":"diet_lifestyle","label":"Diet and lifestyle choices","maps_to":{"dimension":"ai.opinion_limits","value":"lifestyle"}},{"value":"career","label":"My career choices — I want information, not judgment","maps_to":{"dimension":"ai.opinion_limits","value":"career"}},{"value":"ethics_morality","label":"Ethical and moral questions — I can reason through those myself","maps_to":{"dimension":"ai.opinion_limits","value":"ethics"}},{"value":"none","label":"None — I welcome AI perspectives on anything I ask","maps_to":{"dimension":"ai.opinion_limits","value":"open"}}],"skippable":true,"meta_profiling":"Hard limits reveal values and autonomy needs. People who select career/lifestyle limits are typically independent thinkers who don't want AI paternalism. Note combined with proactivity preference.","dimension":"ai.opinion_limits","why_this_matters":"AI respects your intellectual autonomy. These are your no-go zones — it provides information and analysis but holds its opinions."},{"id":"t8_q11","tier":8,"tier_name":"AI Relationship","question":"AI gets significantly better at your specific job. You feel...","type":"scenario","options":[{"value":"excited","label":"Excited — more leverage, more output, I'll do more with AI alongside me","maps_to":{"dimension":"ai.replacement_attitude","value":"augmentation_focused"}},{"value":"curious_adapting","label":"Curious but adapting — I'll need to stay ahead of it, shift to higher-level work","maps_to":{"dimension":"ai.replacement_attitude","value":"adaptive"}},{"value":"concerned","label":"Genuinely concerned — the economics of my work could change in bad ways","maps_to":{"dimension":"ai.replacement_attitude","value":"concerned"},"triggers":["t8_q11a"]},{"value":"not_my_field","label":"Not relevant to my field — AI won't do what I do well enough","maps_to":{"dimension":"ai.replacement_attitude","value":"insulated"}},{"value":"complex","label":"Complex feelings — part excited, part unsettled","maps_to":{"dimension":"ai.replacement_attitude","value":"ambivalent"}}],"skippable":true,"meta_profiling":"This is partly a future-orientation question. Excited/adaptive = high agency. Concerned = worth exploring but not dwelling. Insulated can be denial or genuine differentiation — hard to tell without domain context.","dimension":"ai.replacement_attitude","why_this_matters":"AI adjusts how it frames its own capabilities — not hiding them, but framing augmentation honestly rather than threatening."},{"id":"t8_q11a","tier":8,"tier_name":"AI Relationship","question":"What part of your work are you most worried AI could displace?","type":"open_text","is_followup":true,"parent_question":"t8_q11","placeholder":"Being honest here helps AI focus on areas where your human judgment genuinely adds value vs where automation is coming regardless","skippable":true,"meta_profiling":"Specificity of concern reveals self-awareness about the real threat vs vague AI anxiety. Specific answers warrant honest discussion.","dimension":"ai.displacement_concern","why_this_matters":"AI can help you identify and develop the aspects of your work that are genuinely hard to automate — rather than pretending the concern doesn't exist."},{"id":"t8_q12","tier":8,"tier_name":"AI Relationship","question":"Have you ever written custom instructions for an AI — a system prompt, a 'how to talk to me' section, anything like that?","type":"select","options":[{"value":"yes_advanced","label":"Yes — I've written detailed prompts or system instructions","maps_to":{"dimension":"ai.customization_experience","value":"advanced"}},{"value":"yes_basic","label":"Yes — basic stuff like 'be concise' or 'always respond in X language'","maps_to":{"dimension":"ai.customization_experience","value":"basic"}},{"value":"no_but_want","label":"No, but that's basically what I'm doing right now with Meport","maps_to":{"dimension":"ai.customization_experience","value":"first_time"}},{"value":"no","label":"No — I didn't know that was a thing","maps_to":{"dimension":"ai.customization_experience","value":"none"}}],"skippable":true,"meta_profiling":"Advanced customization experience means they'll appreciate the Meport output and know how to use it well. None/first-time = need to explain what the export does.","dimension":"ai.customization_experience","why_this_matters":"Determines how Meport explains the export — technical detail for experienced users, step-by-step for first-timers."},{"id":"t8_q13","tier":8,"tier_name":"AI Relationship","question":"Which AI platforms do you use regularly?","type":"multi_select","options":[{"value":"chatgpt","label":"ChatGPT (OpenAI)","maps_to":{"dimension":"ai.platforms","value":"chatgpt"}},{"value":"claude","label":"Claude (Anthropic)","maps_to":{"dimension":"ai.platforms","value":"claude"}},{"value":"gemini","label":"Gemini (Google)","maps_to":{"dimension":"ai.platforms","value":"gemini"}},{"value":"copilot","label":"GitHub Copilot / Cursor / Windsurf","maps_to":{"dimension":"ai.platforms","value":"coding_ai"}},{"value":"perplexity","label":"Perplexity","maps_to":{"dimension":"ai.platforms","value":"perplexity"}},{"value":"midjourney_dalle","label":"Midjourney / DALL-E / image tools","maps_to":{"dimension":"ai.platforms","value":"image_ai"}},{"value":"custom_gpts","label":"Custom GPTs or specific AI apps","maps_to":{"dimension":"ai.platforms","value":"custom"}},{"value":"local_models","label":"Local models (Ollama, LM Studio)","maps_to":{"dimension":"ai.platforms","value":"local"}},{"value":"none_regular","label":"None regularly — still getting started","maps_to":{"dimension":"ai.platforms","value":"minimal"}}],"skippable":true,"meta_profiling":"Platform mix reveals sophistication and workflow integration. Coding AI + local models = advanced engineer. ChatGPT only = mass market user. Multiple platforms = platform-agnostic power user.","dimension":"ai.platforms","why_this_matters":"Meport generates export files optimized for the platforms you actually use — no point creating a Claude system prompt if you only use ChatGPT."},{"id":"t8_q14","tier":8,"tier_name":"AI Relationship","question":"In 5 years, AI in your life will be...","type":"open_text","placeholder":"What do you actually think? Not what you're supposed to say — what do you expect and hope for?","skippable":true,"meta_profiling":"The richest free-text in the tier. Utopian, dystopian, pragmatic, or dismissive responses all reveal deep relationship to technology and change. Note: specific predictions vs vague hopes, individual vs societal framing.","dimension":"ai.future_vision","why_this_matters":"Reveals underlying beliefs and concerns about AI that shape how you want it to behave today — and what you're ultimately building toward."},{"id":"t8_q15","tier":8,"tier_name":"AI Relationship","question":"Looking back at this whole profiling session — anything you want to add, correct, or emphasize?","type":"open_text","placeholder":"Anything the questions missed, something you answered wrong, or a final thought. This is your last override before your profile is compiled.","skippable":true,"meta_profiling":"Post-profiling reflection captures anything the structured questions missed. Also reveals their overall attitude to the process — engaged vs exhausted vs skeptical. Note if they correct a previous answer (high self-monitoring) or add something entirely new (dimensions we missed).","dimension":"ai.final_override","why_this_matters":"Your words here go directly into the profile as a top-priority instruction. Anything you say overrides what the structured questions inferred."}]`),m={tier:K,tier_name:Q,tier_intro:X,tier_complete:Z,questions:ee},se=[t,i,o,n,s,r,l,u,m],re=[t,i,o],a=new Set(["t0_q01","t0_q02","t0_q06","t0_q07","t0_q09"]),te={tier:0,tier_name:"Identity",tier_intro:"5 quick questions — AI will figure out the rest from your answers.",tier_complete:{headline:"Seeds planted.",body:"AI is now analyzing your answers to build a deep profile. This is where the magic happens."},questions:t.questions.filter(e=>a.has(e.id)||e.is_followup&&e.parent_question&&a.has(e.parent_question))},le=[te],ie=new Set(["t0_q01","t0_q06","t0_q07","t1_q01","t1_q09","t2_q15"]),oe=new Set(["t0_q07","t1_q01"]),ae=[...t.questions,...i.questions,...o.questions],ne={tier:0,tier_name:"Twój profil AI",tier_intro:"Kilka kluczowych pytań — AI zbuduje resztę z Twoich odpowiedzi.",tier_complete:{headline:"Gotowe.",body:"AI analizuje Twoje odpowiedzi i buduje pełny profil osobowości."},questions:ae.filter(e=>ie.has(e.id)||e.is_followup&&e.parent_question&&oe.has(e.parent_question))},ue=[ne],me=[{tier:0,emoji:"🪪",name:"Identity",questions:t.questions.filter(e=>!e.is_followup).length},{tier:1,emoji:"💬",name:"Communication",questions:i.questions.filter(e=>!e.is_followup).length},{tier:2,emoji:"🧠",name:"Cognitive",questions:o.questions.filter(e=>!e.is_followup).length},{tier:3,emoji:"⚡",name:"Work",questions:n.questions.filter(e=>!e.is_followup).length},{tier:4,emoji:"🎭",name:"Personality",questions:s.questions.filter(e=>!e.is_followup).length},{tier:5,emoji:"🔮",name:"Neurodivergent",questions:r.questions.filter(e=>!e.is_followup).length},{tier:6,emoji:"🛠",name:"Expertise",questions:l.questions.filter(e=>!e.is_followup).length},{tier:7,emoji:"🌍",name:"Life Context",questions:u.questions.filter(e=>!e.is_followup).length},{tier:8,emoji:"🤖",name:"AI Relationship",questions:m.questions.filter(e=>!e.is_followup).length}];export{le as aiTiers,ue as essentialTiers,se as personalTiers,re as quickTiers,me as tierMeta};
